

SET client_encoding = 'UTF8';

DROP TABLE IF EXISTS pokemon_attaque CASCADE;
DROP TABLE IF EXISTS pokemon_talent CASCADE;
DROP TABLE IF EXISTS pokemon_type CASCADE;
DROP TABLE IF EXISTS evolution CASCADE;
DROP TABLE IF EXISTS type_faiblesse CASCADE;
DROP TABLE IF EXISTS attaque CASCADE;
DROP TABLE IF EXISTS talent CASCADE;
DROP TABLE IF EXISTS pokemon CASCADE;
DROP TABLE IF EXISTS type CASCADE;
DROP TABLE IF EXISTS generation CASCADE;

-- ============================================
-- CRÉATION DES TABLES
-- ============================================

CREATE TABLE generation (
    id INTEGER PRIMARY KEY,
    nom VARCHAR(50) NOT NULL,
    region VARCHAR(50)
);

CREATE TABLE type (
    id INTEGER PRIMARY KEY,
    nom VARCHAR(30) NOT NULL UNIQUE,
    couleur VARCHAR(7) DEFAULT '#888888'
);

CREATE TABLE type_faiblesse (
    type_attaquant_id INTEGER NOT NULL REFERENCES type(id),
    type_defenseur_id INTEGER NOT NULL REFERENCES type(id),
    multiplicateur DECIMAL(3,1) NOT NULL,
    PRIMARY KEY (type_attaquant_id, type_defenseur_id)
);

CREATE TABLE pokemon (
    id SERIAL PRIMARY KEY,
    nom VARCHAR(100) NOT NULL,
    numero INTEGER,
    pv INTEGER DEFAULT 0,
    attaque INTEGER DEFAULT 0,
    defense INTEGER DEFAULT 0,
    atk_spe INTEGER DEFAULT 0,
    def_spe INTEGER DEFAULT 0,
    vitesse INTEGER DEFAULT 0,
    taille INTEGER DEFAULT 0,
    poids INTEGER DEFAULT 0,
    description TEXT,
    generation_id INTEGER REFERENCES generation(id),
    image_url TEXT,
    is_custom BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMP DEFAULT NOW()
);

CREATE TABLE pokemon_type (
    pokemon_id INTEGER NOT NULL REFERENCES pokemon(id) ON DELETE CASCADE,
    type_id INTEGER NOT NULL REFERENCES type(id),
    PRIMARY KEY (pokemon_id, type_id)
);

CREATE TABLE talent (
    id INTEGER PRIMARY KEY,
    nom VARCHAR(100) NOT NULL UNIQUE,
    description TEXT
);

CREATE TABLE pokemon_talent (
    pokemon_id INTEGER NOT NULL REFERENCES pokemon(id) ON DELETE CASCADE,
    talent_id INTEGER NOT NULL REFERENCES talent(id),
    est_cache BOOLEAN DEFAULT FALSE,
    PRIMARY KEY (pokemon_id, talent_id)
);

CREATE TABLE attaque (
    id INTEGER PRIMARY KEY,
    nom VARCHAR(100) NOT NULL UNIQUE,
    type_id INTEGER REFERENCES type(id),
    puissance INTEGER,
    precision INTEGER,
    categorie VARCHAR(20)
);

CREATE TABLE pokemon_attaque (
    pokemon_id INTEGER NOT NULL REFERENCES pokemon(id) ON DELETE CASCADE,
    attaque_id INTEGER NOT NULL REFERENCES attaque(id),
    PRIMARY KEY (pokemon_id, attaque_id)
);

CREATE TABLE evolution (
    id SERIAL PRIMARY KEY,
    pokemon_source_id INTEGER NOT NULL REFERENCES pokemon(id),
    pokemon_cible_id INTEGER NOT NULL REFERENCES pokemon(id),
    condition VARCHAR(100)
);

-- Index pour les performances
CREATE INDEX idx_pokemon_nom ON pokemon(nom);
CREATE INDEX idx_pokemon_generation ON pokemon(generation_id);
CREATE INDEX idx_pokemon_type ON pokemon_type(type_id);
CREATE INDEX idx_pokemon_custom ON pokemon(is_custom);

