INSERT INTO talent (id, nom, description) VALUES (289, 'hadron-engine', 'Turns the ground into Electric Terrain when the Pokémon enters a battle. The futuristic engine within the Pokémon also boosts its Sp. Atk stat on Electric Terrain.');
