INSERT INTO talent (id, nom, description) VALUES (301, 'hospitality', 'When the Pokémon enters a battle, it showers its ally with hospitality, restoring a small amount of the ally''s HP');
INSERT INTO talent (id, nom, description) VALUES (302, 'toxic-chain', 'The power of the Pokémon''s toxic chain may badly poison any target the Pokémon hits with a move');
INSERT INTO talent (id, nom, description) VALUES (304, 'tera-shift', 'When the Pokémon enters a battle, it absorbs the energy around itself and transforms into its Terastal Form.');
INSERT INTO talent (id, nom, description) VALUES (307, 'poison-puppeteer', 'Pokémon poisoned by Pecharunt''s moves will also become confused.');
