INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1, 'bulbasaur', 1, 45, 49, 49, 65, 65, 45, 7, 69, 'A strange seed was planted on its back at birth. The plant sprouts and grows with this POKéMON.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (2, 'ivysaur', 2, 60, 62, 63, 80, 80, 60, 10, 130, 'When the bulb on its back grows large, it appears to lose the ability to stand on its hind legs.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/2.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (3, 'venusaur', 3, 80, 82, 83, 100, 100, 80, 20, 1000, 'The plant blooms when it is absorbing solar energy. It stays on the move to seek sunlight.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/3.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (4, 'charmander', 4, 39, 52, 43, 60, 50, 65, 6, 85, 'Obviously prefers hot places. When it rains, steam is said to spout from the tip of its tail.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/4.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (5, 'charmeleon', 5, 58, 64, 58, 80, 65, 80, 11, 190, 'When it swings its burning tail, it elevates the temperature to unbearably high levels.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/5.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (6, 'charizard', 6, 78, 84, 78, 109, 85, 100, 17, 905, 'Spits fire that is hot enough to melt boulders. Known to cause forest fires unintentionally.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/6.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (7, 'squirtle', 7, 44, 48, 65, 50, 64, 43, 5, 90, 'After birth, its back swells and hardens into a shell. Powerfully sprays foam from its mouth.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/7.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (8, 'wartortle', 8, 59, 63, 80, 65, 80, 58, 10, 225, 'Often hides in water to stalk unwary prey. For swimming fast, it moves its ears to maintain balance.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/8.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (9, 'blastoise', 9, 79, 83, 100, 85, 105, 78, 16, 855, 'A brutal POKéMON with pressurized water jets on its shell. They are used for high speed tackles.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/9.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (10, 'caterpie', 10, 45, 30, 35, 20, 20, 45, 3, 29, 'Its short feet are tipped with suction pads that enable it to tirelessly climb slopes and walls.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/10.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (11, 'metapod', 11, 50, 20, 55, 25, 25, 30, 7, 99, 'This POKéMON is vulnerable to attack while its shell is soft, exposing its weak and tender body.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/11.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (12, 'butterfree', 12, 60, 45, 50, 90, 80, 70, 11, 320, 'In battle, it flaps its wings at high speed to release highly toxic dust into the air.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/12.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (13, 'weedle', 13, 40, 35, 30, 20, 20, 50, 3, 32, 'Often found in forests, eating leaves. It has a sharp venomous stinger on its head.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/13.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (14, 'kakuna', 14, 45, 25, 50, 25, 25, 35, 6, 100, 'Almost incapable of moving, this POKéMON can only harden its shell to protect itself from predators.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/14.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (15, 'beedrill', 15, 65, 90, 40, 45, 80, 75, 10, 295, 'It has three poisonous stingers on its forelegs and its tail. They are used to jab its enemy repeatedly.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/15.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (16, 'pidgey', 16, 40, 45, 40, 35, 35, 56, 3, 18, 'A common sight in forests and woods. It flaps its wings at ground level to kick up blinding sand.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/16.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (17, 'pidgeotto', 17, 63, 60, 55, 50, 50, 71, 11, 300, 'Very protective of its sprawling territorial area, this POKéMON will fiercely peck at any intruder.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/17.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (18, 'pidgeot', 18, 83, 80, 75, 70, 70, 101, 15, 395, 'When hunting, it skims the surface of water at high speed to pick off unwary prey such as MAGIKARP.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/18.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (19, 'rattata', 19, 30, 56, 35, 25, 35, 72, 3, 35, 'Bites anything when it attacks. Small and very quick, it is a common sight in many places.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/19.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (20, 'raticate', 20, 55, 81, 60, 50, 70, 97, 7, 185, 'It uses its whis­ kers to maintain its balance. It apparently slows down if they are cut off.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/20.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (21, 'spearow', 21, 40, 60, 30, 31, 31, 70, 3, 20, 'It flaps its small wings busily to fly. Using its beak, it searches in grass for prey.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/21.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (22, 'fearow', 22, 65, 90, 65, 61, 61, 100, 12, 380, 'With its huge and magnificent wings, it can keep aloft without ever having to land for rest.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/22.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (23, 'ekans', 23, 35, 60, 44, 40, 54, 55, 20, 69, 'Moves silently and stealthily. Eats the eggs of birds, such as PIDGEY and SPEAROW, whole.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/23.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (24, 'arbok', 24, 60, 95, 69, 65, 79, 80, 35, 650, 'It is rumored that the ferocious warning markings on its belly differ from area to area.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/24.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (25, 'pikachu', 25, 35, 55, 40, 50, 50, 90, 4, 60, 'When several of these POKéMON gather, their electricity could build and cause lightning storms.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/25.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (26, 'raichu', 26, 60, 90, 55, 90, 80, 110, 8, 300, 'Its long tail serves as a ground to protect itself from its own high-voltage power.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/26.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (27, 'sandshrew', 27, 50, 75, 85, 20, 30, 40, 6, 120, 'Burrows deep underground in arid locations far from water. It only emerges to hunt for food.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/27.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (28, 'sandslash', 28, 75, 100, 110, 45, 55, 65, 10, 295, 'Curls up into a spiny ball when threatened. It can roll while curled up to attack or escape.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/28.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (29, 'nidoran-f', 29, 55, 47, 52, 40, 40, 41, 4, 70, 'Although small, its venomous barbs render this POKéMON dangerous. The female has smaller horns.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/29.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (30, 'nidorina', 30, 70, 62, 67, 55, 55, 56, 8, 200, 'The female''s horn develops slowly. Prefers physical attacks such as clawing and biting.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/30.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (31, 'nidoqueen', 31, 90, 92, 87, 75, 85, 76, 13, 600, 'Its hard scales provide strong protection. It uses its hefty bulk to execute powerful moves.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/31.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (32, 'nidoran-m', 32, 46, 57, 40, 40, 40, 50, 5, 90, 'Stiffens its ears to sense danger. The larger its horns, the more powerful its secreted venom.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/32.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (33, 'nidorino', 33, 61, 72, 57, 55, 55, 65, 9, 195, 'An aggressive POKéMON that is quick to attack. The horn on its head secretes a powerful venom.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/33.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (34, 'nidoking', 34, 81, 102, 77, 85, 75, 85, 14, 620, 'It uses its powerful tail in battle to smash, constrict, then break the prey''s bones.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/34.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (35, 'clefairy', 35, 70, 45, 48, 60, 65, 35, 6, 75, 'Its magical and cute appeal has many admirers. It is rare and found only in certain areas.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/35.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (36, 'clefable', 36, 95, 70, 73, 95, 90, 60, 13, 400, 'A timid fairy POKéMON that is rarely seen. It will run and hide the moment it senses people.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/36.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (37, 'vulpix', 37, 38, 41, 40, 50, 65, 65, 6, 99, 'At the time of birth, it has just one tail. The tail splits from its tip as it grows older.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/37.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (38, 'ninetales', 38, 73, 76, 75, 81, 100, 100, 11, 199, 'Very smart and very vengeful. Grabbing one of its many tails could result in a 1000-year curse.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/38.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (39, 'jigglypuff', 39, 115, 45, 20, 45, 25, 20, 5, 55, 'When its huge eyes light up, it sings a mysteriously soothing melody that lulls its enemies to sleep.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/39.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (40, 'wigglytuff', 40, 140, 70, 45, 85, 50, 45, 10, 120, 'The body is soft and rubbery. When angered, it will suck in air and inflate itself to an enormous size.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/40.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (41, 'zubat', 41, 40, 45, 35, 30, 40, 55, 8, 75, 'Forms colonies in perpetually dark places. Uses ultrasonic waves to identify and approach targets.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/41.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (42, 'golbat', 42, 75, 80, 70, 65, 75, 90, 16, 550, 'Once it strikes, it will not stop draining energy from the victim even if it gets too heavy to fly.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/42.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (43, 'oddish', 43, 45, 50, 55, 75, 65, 30, 5, 54, 'During the day, it keeps its face buried in the ground. At night, it wanders around sowing its seeds.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/43.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (44, 'gloom', 44, 60, 65, 70, 85, 75, 40, 8, 86, 'The fluid that oozes from its mouth isn''t drool. It is a nectar that is used to attract prey.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/44.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (45, 'vileplume', 45, 75, 80, 85, 110, 90, 50, 12, 186, 'It has the world’s largest petals. With every step, the petals shake out heavy clouds of toxic pollen.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/45.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (46, 'paras', 46, 35, 70, 55, 45, 55, 25, 3, 54, 'Burrows to suck tree roots. The mushrooms on its back grow by draw­ ing nutrients from the bug host.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/46.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (47, 'parasect', 47, 60, 95, 80, 60, 80, 30, 10, 295, 'A host-parasite pair in which the parasite mushroom has taken over the host bug. Prefers damp places.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/47.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (48, 'venonat', 48, 60, 55, 50, 40, 55, 45, 10, 300, 'Lives in the shadows of tall trees where it eats insects. It is attracted by light at night.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/48.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (49, 'venomoth', 49, 70, 65, 60, 90, 75, 90, 15, 125, 'The dustlike scales covering its wings are color-coded to indicate the kinds of poison it has.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/49.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (50, 'diglett', 50, 10, 55, 25, 35, 45, 95, 2, 8, 'Lives about one yard underground where it feeds on plant roots. It sometimes appears above ground.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/50.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (51, 'dugtrio', 51, 35, 100, 50, 50, 70, 120, 7, 333, 'A team of DIGLETT triplets. It triggers huge earthquakes by burrowing 60 miles underground.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/51.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (52, 'meowth', 52, 40, 45, 35, 40, 40, 90, 4, 42, 'It washes its face regularly to keep the coin on its forehead spotless. It doesn’t get along with Galarian Meowth.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/52.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (53, 'persian', 53, 65, 70, 60, 65, 65, 115, 10, 320, 'Although its fur has many admirers, it is tough to raise as a pet because of its fickle meanness.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/53.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (54, 'psyduck', 54, 50, 52, 48, 65, 50, 55, 8, 196, 'While lulling its enemies with its vacant look, this wily POKéMON will use psychokinetic powers.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/54.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (55, 'golduck', 55, 80, 82, 78, 95, 80, 85, 17, 766, 'Often seen swim­ ming elegantly by lake shores. It is often mistaken for the Japanese monster, Kappa.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/55.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (56, 'mankey', 56, 40, 80, 35, 35, 45, 70, 5, 280, 'Extremely quick to anger. It could be docile one moment then thrashing away the next instant.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/56.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (57, 'primeape', 57, 65, 105, 60, 60, 70, 95, 10, 320, 'Always furious and tenacious to boot. It will not abandon chasing its quarry until it is caught.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/57.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (58, 'growlithe', 58, 55, 70, 45, 70, 50, 60, 7, 190, 'Very protective of its territory. It will bark and bite to repel intruders from its space.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/58.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (59, 'arcanine', 59, 90, 110, 80, 100, 80, 95, 19, 1550, 'A POKéMON that has been admired since the past for its beauty. It runs agilely as if on wings.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/59.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (60, 'poliwag', 60, 40, 50, 40, 40, 40, 90, 6, 124, 'Its newly grown legs prevent it from running. It appears to prefer swimming than trying to stand.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/60.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (61, 'poliwhirl', 61, 65, 65, 65, 50, 50, 90, 10, 200, 'Capable of living in or out of water. When out of water, it sweats to keep its body slimy.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/61.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (62, 'poliwrath', 62, 90, 95, 95, 70, 90, 70, 13, 540, 'An adept swimmer at both the front crawl and breast stroke. Easily overtakes the best human swimmers.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/62.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (63, 'abra', 63, 25, 20, 15, 105, 55, 90, 9, 195, 'Using its ability to read minds, it will identify impending danger and TELEPORT to safety.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/63.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (64, 'kadabra', 64, 40, 35, 30, 120, 70, 105, 13, 565, 'It emits special alpha waves from its body that induce headaches just by being close by.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/64.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (65, 'alakazam', 65, 55, 50, 45, 135, 95, 120, 15, 480, 'Its brain can out­ perform a super­ computer. Its intelligence quotient is said to be 5,000.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/65.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (66, 'machop', 66, 70, 80, 50, 35, 35, 35, 8, 195, 'Loves to build its muscles. It trains in all styles of martial arts to become even stronger.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/66.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (67, 'machoke', 67, 80, 100, 70, 50, 60, 45, 15, 705, 'Its muscular body is so powerful, it must wear a power save belt to be able to regulate its motions.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/67.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (68, 'machamp', 68, 90, 130, 80, 65, 85, 55, 16, 1300, 'Using its heavy muscles, it throws powerful punches that can send the victim clear over the horizon.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/68.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (69, 'bellsprout', 69, 50, 75, 35, 70, 30, 40, 7, 40, 'A carnivorous POKéMON that traps and eats bugs. It uses its root feet to soak up needed moisture.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/69.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (70, 'weepinbell', 70, 65, 90, 50, 85, 45, 55, 10, 64, 'It spits out POISONPOWDER to immobilize the enemy and then finishes it with a spray of ACID.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/70.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (71, 'victreebel', 71, 80, 105, 65, 100, 70, 70, 17, 155, 'Said to live in huge colonies deep in jungles, although no one has ever returned from there.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/71.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (72, 'tentacool', 72, 40, 40, 35, 50, 100, 70, 9, 455, 'Drifts in shallow seas. Anglers who hook them by accident are often punished by its stinging acid.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/72.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (73, 'tentacruel', 73, 80, 70, 65, 80, 120, 100, 16, 550, 'The tentacles are normally kept short. On hunts, they are extended to ensnare and immobilize prey.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/73.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (74, 'geodude', 74, 40, 80, 100, 30, 30, 20, 4, 200, 'Found in fields and mountains. Mistaking them for boulders, people often step or trip on them.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/74.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (75, 'graveler', 75, 55, 95, 115, 45, 45, 35, 10, 1050, 'Rolls down slopes to move. It rolls over any obstacle without slowing or changing its direction.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/75.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (76, 'golem', 76, 80, 120, 130, 55, 65, 45, 14, 3000, 'Its boulder-like body is extremely hard. It can easily withstand dynamite blasts without damage.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/76.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (77, 'ponyta', 77, 50, 85, 55, 65, 65, 90, 10, 300, 'Its hooves are 10 times harder than diamonds. It can trample anything completely flat in little time.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/77.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (78, 'rapidash', 78, 65, 100, 70, 80, 80, 105, 17, 950, 'Very competitive, this POKéMON will chase anything that moves fast in the hopes of racing it.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/78.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (79, 'slowpoke', 79, 90, 65, 65, 40, 40, 15, 12, 360, 'Incredibly slow and dopey. It takes 5 seconds for it to feel pain when under attack.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/79.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (80, 'slowbro', 80, 95, 75, 110, 100, 80, 30, 16, 785, 'The SHELLDER that is latched onto SLOWPOKE''s tail is said to feed on the host''s left over scraps.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/80.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (81, 'magnemite', 81, 25, 35, 70, 95, 55, 45, 3, 60, 'Uses anti-gravity to stay suspended. Appears without warning and uses THUNDER WAVE and similar moves.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/81.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (82, 'magneton', 82, 50, 60, 95, 120, 70, 70, 10, 600, 'Formed by several MAGNEMITEs linked together. They frequently appear when sunspots flare up.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/82.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (83, 'farfetchd', 83, 52, 90, 55, 58, 62, 60, 8, 150, 'The sprig of green onions it holds is its weapon. It is used much like a metal sword.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/83.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (84, 'doduo', 84, 35, 85, 45, 35, 35, 75, 14, 392, 'A bird that makes up for its poor flying with its fast foot speed. Leaves giant footprints.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/84.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (85, 'dodrio', 85, 60, 110, 70, 60, 60, 110, 18, 852, 'Uses its three brains to execute complex plans. While two heads sleep, one head stays awake.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/85.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (86, 'seel', 86, 65, 45, 55, 45, 70, 45, 11, 900, 'The protruding horn on its head is very hard. It is used for bashing through thick ice.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/86.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (87, 'dewgong', 87, 90, 70, 80, 70, 95, 70, 17, 1200, 'Stores thermal energy in its body. Swims at a steady 8 knots even in intensely cold waters.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/87.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (88, 'grimer', 88, 80, 80, 50, 40, 50, 25, 9, 300, 'Appears in filthy areas. Thrives by sucking up polluted sludge that is pumped out of factories.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/88.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (89, 'muk', 89, 105, 105, 75, 65, 100, 50, 12, 300, 'Thickly covered with a filthy, vile sludge. It is so toxic, even its footprints contain poison.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/89.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (90, 'shellder', 90, 30, 65, 100, 45, 25, 40, 3, 40, 'Its hard shell repels any kind of attack. It is vulnerable only when its shell is open.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/90.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (91, 'cloyster', 91, 50, 95, 180, 85, 45, 70, 15, 1325, 'When attacked, it launches its horns in quick volleys. Its innards have never been seen.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/91.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (92, 'gastly', 92, 30, 35, 30, 100, 35, 80, 13, 1, 'Almost invisible, this gaseous POKéMON cloaks the target and puts it to sleep without notice.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/92.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (93, 'haunter', 93, 45, 50, 45, 115, 55, 95, 16, 1, 'Because of its ability to slip through block walls, it is said to be from an­ other dimension.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/93.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (94, 'gengar', 94, 60, 65, 60, 130, 75, 110, 15, 405, 'Under a full moon, this POKéMON likes to mimic the shadows of people and laugh at their fright.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/94.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (95, 'onix', 95, 35, 45, 160, 30, 45, 70, 88, 2100, 'As it grows, the stone portions of its body harden to become similar to a diamond, but colored black.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/95.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (96, 'drowzee', 96, 60, 48, 45, 43, 90, 42, 10, 324, 'Puts enemies to sleep then eats their dreams. Occasionally gets sick from eating bad dreams.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/96.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (97, 'hypno', 97, 85, 73, 70, 73, 115, 67, 16, 756, 'When it locks eyes with an enemy, it will use a mix of PSI moves such as HYPNOSIS and CONFUSION.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/97.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (98, 'krabby', 98, 30, 105, 90, 25, 25, 50, 4, 65, 'Its pincers are not only powerful weapons, they are used for balance when walking sideways.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/98.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (99, 'kingler', 99, 55, 130, 115, 50, 50, 75, 13, 600, 'The large pincer has 10000 hp of crushing power. However, its huge size makes it unwieldy to use.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/99.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (100, 'voltorb', 100, 40, 30, 50, 55, 55, 100, 5, 104, 'Usually found in power plants. Easily mistaken for a POKé BALL, they have zapped many people.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/100.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (101, 'electrode', 101, 60, 50, 70, 80, 80, 150, 12, 666, 'It stores electric energy under very high pressure. It often explodes with little or no provocation.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/101.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (102, 'exeggcute', 102, 60, 40, 80, 60, 45, 40, 4, 25, 'Often mistaken for eggs. When disturbed, they quickly gather and attack in swarms.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/102.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (103, 'exeggutor', 103, 95, 95, 85, 125, 75, 55, 20, 1200, 'Legend has it that on rare occasions, one of its heads will drop off and continue on as an EXEGGCUTE.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/103.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (104, 'cubone', 104, 50, 50, 95, 40, 50, 35, 4, 65, 'Because it never removes its skull helmet, no one has ever seen this POKéMON''s real face.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/104.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (105, 'marowak', 105, 60, 80, 110, 50, 80, 45, 10, 450, 'The bone it holds is its key weapon. It throws the bone skillfully like a boomerang to KO targets.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/105.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (106, 'hitmonlee', 106, 50, 120, 53, 35, 110, 87, 15, 498, 'When in a hurry, its legs lengthen progressively. It runs smoothly with extra long, loping strides.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/106.png', FALSE);
