INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (108, 'lickitung', 108, 90, 55, 75, 60, 75, 30, 12, 655, 'Its tongue can be extended like a chameleon''s. It leaves a tingling sensation when it licks enemies.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/108.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (109, 'koffing', 109, 40, 65, 95, 60, 45, 35, 6, 10, 'Because it stores several kinds of toxic gases in its body, it is prone to exploding without warning.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/109.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (110, 'weezing', 110, 65, 90, 120, 85, 70, 60, 12, 95, 'Where two kinds of poison gases meet, 2 KOFFINGs can fuse into a WEEZING over many years.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/110.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (111, 'rhyhorn', 111, 80, 85, 95, 30, 30, 25, 10, 1150, 'A POKéMON with a one-track mind. Once it charges,  it won''t stop running until it falls asleep.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/111.png', FALSE);
