INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (119, 'seaking', 119, 80, 92, 65, 65, 80, 68, 13, 390, 'In the autumn spawning season, they can be seen swimming powerfully up rivers and creeks.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/119.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (120, 'staryu', 120, 30, 45, 55, 70, 55, 85, 8, 345, 'If its body is torn, it can grow back if the red core remains. The core flashes at midnight.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/120.png', FALSE);
