INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (122, 'mr-mime', 122, 40, 45, 65, 100, 120, 90, 13, 545, 'If interrupted while it is miming, it will slap around the offender with its broad hands.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/122.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (123, 'scyther', 123, 70, 110, 80, 55, 80, 105, 15, 560, 'With ninja-like agility and speed, it can create the illusion that there is more than one.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/123.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (124, 'jynx', 124, 65, 50, 35, 115, 95, 95, 14, 406, 'It seductively wiggles its hips as it walks. It can cause people to dance in unison with it.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/124.png', FALSE);
