INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (126, 'magmar', 126, 65, 95, 57, 100, 85, 93, 13, 445, 'Its body always burns with an orange glow that enables it to hide perfectly among flames.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/126.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (127, 'pinsir', 127, 65, 125, 100, 55, 70, 85, 15, 550, 'If it fails to crush the victim in its pincers, it will swing it around and toss it hard.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/127.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (128, 'tauros', 128, 75, 100, 95, 40, 70, 110, 14, 884, 'When it targets an enemy, it charges furiously while whipping its body with its long tails.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/128.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (129, 'magikarp', 129, 20, 10, 55, 15, 20, 80, 9, 100, 'In the distant past, it was somewhat stronger than the horribly weak descendants that exist today.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/129.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (130, 'gyarados', 130, 95, 125, 79, 60, 100, 81, 65, 2350, 'Once it begins to rampage, a GYARADOS will burn everything down, even in a harsh storm.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/130.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (131, 'lapras', 131, 130, 85, 80, 85, 95, 60, 25, 2200, 'A POKéMON that has been over­ hunted almost to extinction. It can ferry people across the water.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/131.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (132, 'ditto', 132, 48, 48, 48, 48, 48, 48, 3, 40, 'Capable of copying an enemy''s genetic code to instantly transform itself into a duplicate of the enemy.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/132.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (133, 'eevee', 133, 55, 55, 50, 45, 65, 55, 3, 65, 'Its genetic code is irregular. It may mutate if it is exposed to radiation from element STONEs.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/133.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (134, 'vaporeon', 134, 130, 65, 60, 110, 95, 65, 10, 290, 'Lives close to water. Its long tail is ridged with a fin which is often mistaken for a mermaid''s.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/134.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (135, 'jolteon', 135, 65, 65, 60, 110, 95, 130, 8, 245, 'It accumulates negative ions in the atmosphere to blast out 10000- volt lightning bolts.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/135.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (136, 'flareon', 136, 65, 130, 60, 95, 110, 65, 9, 250, 'When storing thermal energy in its body, its temperature could soar to over 1600 degrees.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/136.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (137, 'porygon', 137, 65, 60, 70, 85, 75, 40, 8, 365, 'A POKéMON that consists entirely of programming code. Capable of moving freely in cyberspace.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/137.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (138, 'omanyte', 138, 35, 40, 100, 90, 55, 35, 4, 75, 'Although long extinct, in rare cases, it can be genetically resurrected from fossils.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/138.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (139, 'omastar', 139, 70, 60, 125, 115, 70, 55, 10, 350, 'A prehistoric POKéMON that died out when its heavy shell made it impossible to catch prey.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/139.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (140, 'kabuto', 140, 30, 80, 90, 55, 45, 55, 5, 115, 'A POKéMON that was resurrected from a fossil found in what was once the ocean floor eons ago.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/140.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (141, 'kabutops', 141, 60, 115, 105, 65, 70, 80, 13, 405, 'Its sleek shape is perfect for swim­ ming. It slashes prey with its claws and drains the body fluids.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/141.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (142, 'aerodactyl', 142, 80, 105, 65, 60, 75, 130, 18, 590, 'A Pokémon that roamed the skies in the dinosaur era. Its teeth are like saw blades.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/142.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (143, 'snorlax', 143, 160, 110, 65, 65, 110, 30, 21, 4600, 'Very lazy. Just eats and sleeps. As its rotund bulk builds, it becomes steadily more slothful.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/143.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (144, 'articuno', 144, 90, 85, 100, 95, 125, 85, 17, 554, 'A legendary bird POKéMON that is said to appear to doomed people who are lost in icy mountains.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/144.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (145, 'zapdos', 145, 90, 90, 85, 125, 90, 100, 16, 526, 'A legendary bird POKéMON that is said to appear from clouds while dropping enormous lightning bolts.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/145.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (146, 'moltres', 146, 90, 100, 90, 125, 85, 90, 20, 600, 'Known as the legendary bird of fire. Every flap of its wings creates a dazzling flash of flames.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/146.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (147, 'dratini', 147, 41, 64, 45, 50, 50, 50, 18, 33, 'Long considered a mythical POKéMON until recently when a small colony was found living underwater.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/147.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (148, 'dragonair', 148, 61, 84, 65, 70, 70, 70, 40, 165, 'A mystical POKéMON that exudes a gentle aura. Has the ability to change climate conditions.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/148.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (149, 'dragonite', 149, 91, 134, 95, 100, 100, 80, 22, 2100, 'An extremely rarely seen marine POKéMON. Its intelligence is said to match that of humans.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/149.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (150, 'mewtwo', 150, 106, 110, 90, 154, 90, 130, 20, 1220, 'It was created by a scientist after years of horrific gene splicing and DNA engineering experiments.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/150.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (151, 'mew', 151, 100, 100, 100, 100, 100, 100, 4, 40, 'So rare that it is still said to be a mirage by many experts. Only a few people have seen it worldwide.', 1, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/151.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (152, 'chikorita', 152, 45, 49, 65, 49, 65, 45, 9, 64, 'A sweet aroma gently wafts from the leaf on its head. It is docile and loves to soak up the sun''s rays.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/152.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (153, 'bayleef', 153, 60, 62, 80, 63, 80, 60, 12, 158, 'The scent of spices comes from around its neck. Somehow, sniffing it makes you want to fight.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/153.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (154, 'meganium', 154, 80, 82, 100, 83, 100, 80, 18, 1005, 'The aroma that rises from its petals contains a substance that calms aggressive feelings.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/154.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (155, 'cyndaquil', 155, 39, 52, 43, 60, 50, 65, 5, 79, 'It has a timid nature. If it is startled, the flames on its back burn more vigorously.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/155.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (156, 'quilava', 156, 58, 64, 58, 80, 65, 80, 9, 190, 'Be careful if it turns its back during battle. It means that it will attack with the fire on its back.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/156.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (157, 'typhlosion', 157, 78, 84, 78, 109, 85, 100, 17, 795, 'If its rage peaks, it becomes so hot that anything that touches it will instantly go up in flames.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/157.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (158, 'totodile', 158, 50, 65, 64, 44, 48, 43, 6, 95, 'Its well-developed jaws are powerful and capable of crushing anything. Even its trainer must be careful.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/158.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (159, 'croconaw', 159, 65, 80, 80, 59, 63, 58, 11, 250, 'If it loses a fang, a new one grows back in its place. There are always 48 fangs lining its mouth.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/159.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (160, 'feraligatr', 160, 85, 105, 100, 79, 83, 78, 23, 888, 'When it bites with its massive and powerful jaws, it shakes its head and savagely tears its victim up.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/160.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (161, 'sentret', 161, 35, 46, 34, 35, 45, 20, 8, 60, 'A very cautious POKéMON, it raises itself up using its tail to get a better view of its surroundings.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/161.png', FALSE);
