INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (163, 'hoothoot', 163, 60, 30, 30, 36, 56, 50, 7, 212, 'It always stands on one foot. It changes feet so fast, the movement can rarely be seen.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/163.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (164, 'noctowl', 164, 100, 50, 50, 86, 96, 70, 16, 408, 'Its eyes are specially adapted. They concentrate even faint light and enable it to see in the dark.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/164.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (165, 'ledyba', 165, 40, 20, 30, 40, 80, 55, 10, 108, 'It is very timid. It will be afraid to move if it is alone. But it will be active if it is in a group.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/165.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (166, 'ledian', 166, 55, 35, 50, 55, 110, 85, 14, 356, 'When the stars flicker in the night sky, it flutters about, scattering a glowing powder.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/166.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (167, 'spinarak', 167, 40, 60, 40, 40, 40, 30, 5, 85, 'It lies still in the same pose for days in its web, waiting for its unsuspecting prey to wander close.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/167.png', FALSE);
