INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (169, 'crobat', 169, 85, 90, 80, 70, 80, 130, 18, 750, 'It flies so si­ lently through the dark on its four wings that it may not be noticed even when nearby.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/169.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (170, 'chinchou', 170, 75, 38, 38, 56, 56, 67, 5, 120, 'Chinchou blink their shining antennae at one another to claim their respective turf.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/170.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (171, 'lanturn', 171, 125, 58, 58, 76, 76, 67, 12, 225, 'The light it emits is so bright that it can illuminate the sea''s surface from a depth of over three miles.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/171.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (172, 'pichu', 172, 20, 40, 15, 35, 35, 60, 3, 20, 'It is not yet skilled at storing electricity. It may send out a jolt if amused or startled.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/172.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (173, 'cleffa', 173, 50, 25, 28, 45, 55, 15, 3, 30, 'Because of its unusual, star-like silhouette, people believe that it came here on a meteor.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/173.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (174, 'igglybuff', 174, 90, 30, 15, 40, 20, 15, 3, 10, 'It has a very soft body. If it starts to roll, it will bounce all over and be impossible to stop.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/174.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (175, 'togepi', 175, 35, 20, 65, 40, 65, 20, 3, 15, 'The shell seems to be filled with joy. It is said that it will share good luck when treated kindly.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/175.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (176, 'togetic', 176, 55, 40, 85, 80, 105, 40, 6, 32, 'They say that it will appear before kindhearted, car­ ing people and shower them with happiness.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/176.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (177, 'natu', 177, 40, 50, 45, 70, 45, 70, 2, 20, 'Because its wings aren''t yet fully grown, it has to hop to get around. It is always star­ ing at something.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/177.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (178, 'xatu', 178, 65, 75, 70, 95, 70, 95, 15, 150, 'They say that it stays still and quiet because it is seeing both the past and future at the same time.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/178.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (179, 'mareep', 179, 55, 40, 40, 65, 45, 35, 6, 78, 'If static elec­ tricity builds in its body, its fleece doubles in volume. Touching it will shock you.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/179.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (180, 'flaaffy', 180, 70, 55, 55, 80, 60, 45, 8, 133, 'As a result of storing too much electricity, it developed patches where even downy wool won''t grow.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/180.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (181, 'ampharos', 181, 90, 75, 85, 115, 90, 55, 14, 615, 'The tail''s tip shines brightly and can be seen from far away. It acts as a beacon for lost people.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/181.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (182, 'bellossom', 182, 75, 80, 95, 90, 100, 50, 4, 58, 'Plentiful in the tropics. When it dances, its petals rub together and make a pleasant ringing sound.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/182.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (183, 'marill', 183, 70, 20, 50, 20, 50, 40, 4, 85, 'The tip of its tail, which con­ tains oil that is lighter than wa­ ter, lets it swim without drowning.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/183.png', FALSE);
