INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (185, 'sudowoodo', 185, 70, 100, 115, 30, 65, 30, 12, 380, 'Although it always pretends to be a tree, its composi­ tion appears to be closer to a rock than a plant.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/185.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (186, 'politoed', 186, 90, 75, 75, 90, 100, 70, 11, 339, 'If POLIWAG and POLIWHIRL hear its echoing cry, they respond by gather­ ing from far and wide.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/186.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (187, 'hoppip', 187, 35, 35, 40, 35, 55, 50, 4, 5, 'To keep from being blown away by the wind, they gather in clusters. They do enjoy gentle breezes, though.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/187.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (188, 'skiploom', 188, 55, 45, 50, 45, 65, 80, 6, 10, 'The bloom on top of its head opens and closes as the temperature fluc­ tuates up and down.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/188.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (189, 'jumpluff', 189, 75, 55, 70, 55, 95, 110, 8, 30, 'Once it catches the wind, it deft­ ly controls its cotton-puff spores to float, even around the world.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/189.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (190, 'aipom', 190, 55, 70, 55, 40, 55, 85, 8, 115, 'Its tail is so powerful that it can use it to grab a tree branch and hold itself up in the air.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/190.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (191, 'sunkern', 191, 30, 30, 30, 30, 30, 30, 3, 18, 'It may drop out of the sky suddenly. If attacked by a SPEAROW, it will violently shake its leaves.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/191.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (192, 'sunflora', 192, 75, 75, 55, 105, 85, 30, 8, 85, 'It converts sun­ light into energy. In the darkness after sunset, it closes its petals and becomes still.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/192.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (193, 'yanma', 193, 65, 65, 45, 75, 45, 95, 12, 380, 'If it flaps its wings really fast, it can generate shock waves that will shatter win­ dows in the area.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/193.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (194, 'wooper', 194, 55, 45, 45, 25, 25, 15, 4, 85, 'This POKéMON lives in cold water. It will leave the water to search for food when it gets cold outside.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/194.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (195, 'quagsire', 195, 95, 85, 85, 65, 65, 35, 14, 750, 'This carefree POKéMON has an easy-going nature. While swimming, it always bumps into boat hulls.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/195.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (196, 'espeon', 196, 65, 65, 60, 130, 95, 110, 9, 265, 'It uses the fine hair that covers its body to sense air currents and predict its ene­ my''s actions.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/196.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (197, 'umbreon', 197, 95, 65, 110, 60, 130, 65, 10, 270, 'When agitated, this POKéMON pro­ tects itself by spraying poisonous sweat from its pores.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/197.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (198, 'murkrow', 198, 60, 85, 42, 85, 42, 91, 5, 21, 'Feared and loathed by many, it is believed to bring misfortune to all those who see it at night.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/198.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (199, 'slowking', 199, 95, 75, 80, 100, 110, 30, 20, 795, 'It has incredible intellect and in­ tuition. Whatever the situation, it remains calm and collected.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/199.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (200, 'misdreavus', 200, 60, 60, 60, 85, 85, 85, 7, 10, 'It likes playing mischievous tricks such as screaming and wailing to startle people at night.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/200.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (201, 'unown', 201, 48, 72, 48, 72, 48, 48, 5, 50, 'Their shapes look like hieroglyphs on ancient tab­ lets. It is said that the two are somehow related.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/201.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (202, 'wobbuffet', 202, 190, 33, 58, 33, 58, 33, 13, 285, 'It hates light and shock. If attack­ ed, it inflates its body to pump up its counter­ strike.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/202.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (203, 'girafarig', 203, 70, 80, 65, 90, 65, 85, 15, 415, 'Its tail has a small brain of its own. Beware! If you get close, it may react to your scent and bite.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/203.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (204, 'pineco', 204, 50, 65, 90, 35, 35, 15, 6, 72, 'It likes to make its shell thicker by adding layers of tree bark. The additional weight doesn''t bother it.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/204.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (205, 'forretress', 205, 75, 90, 140, 60, 60, 40, 12, 1258, 'Its entire body is shielded by a steel-hard shell. What lurks inside the armor is a total mystery.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/205.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (206, 'dunsparce', 206, 100, 70, 70, 65, 65, 45, 15, 140, 'When spotted, this POKéMON escapes backward by furi­ ously boring into the ground with its tail.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/206.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (207, 'gligar', 207, 65, 75, 105, 35, 65, 85, 11, 648, 'It flies straight at its target''s face then clamps down on the star­ tled victim to inject poison.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/207.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (208, 'steelix', 208, 75, 85, 200, 55, 65, 30, 92, 4000, 'It is thought its body transformed as a result of iron accumulating internally from swallowing soil.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/208.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (209, 'snubbull', 209, 60, 80, 50, 40, 40, 30, 6, 78, 'Although it looks frightening, it is actually kind and affectionate. It is very popular among women.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/209.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (210, 'granbull', 210, 90, 120, 75, 60, 60, 45, 14, 487, 'It is actually timid and easily spooked. If at­ tacked, it flails about to fend off its attacker.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/210.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (211, 'qwilfish', 211, 65, 95, 85, 55, 55, 85, 5, 39, 'To fire its poison spikes, it must inflate its body by drinking over 2.6 gallons of water all at once.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/211.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (212, 'scizor', 212, 70, 130, 100, 55, 80, 65, 18, 1180, 'It has a steel-hard body. It intimidates foes by upraising its eye-patterned pincers.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/212.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (213, 'shuckle', 213, 20, 10, 230, 10, 230, 5, 6, 205, 'The BERRIES it stores in its vase-like shell decompose and become a gooey liquid.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/213.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (214, 'heracross', 214, 80, 125, 75, 40, 95, 85, 15, 540, 'It is usually docile, but if it is disturbed while sipping honey, it chases off the intruder with its horn.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/214.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (215, 'sneasel', 215, 55, 95, 55, 35, 75, 115, 9, 280, 'Its paws conceal sharp claws. If attacked, it sud­ denly extends the claws and startles its enemy.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/215.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (216, 'teddiursa', 216, 60, 80, 50, 50, 50, 40, 6, 88, 'If it finds honey, its crescent mark glows. It always licks its paws because they are soaked with honey.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/216.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (217, 'ursaring', 217, 90, 130, 75, 75, 75, 55, 18, 1258, 'Although it is a good climber, it prefers to snap trees with its forelegs and eat fallen BERRIES.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/217.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (218, 'slugma', 218, 40, 40, 40, 70, 40, 20, 7, 350, 'It never sleeps. It has to keep moving because if it stopped, its magma body would cool and harden.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/218.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (219, 'magcargo', 219, 60, 50, 120, 90, 80, 30, 8, 550, 'The shell on its back is just skin that has cooled and hardened. It breaks easily with a slight touch.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/219.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (220, 'swinub', 220, 50, 50, 40, 30, 30, 50, 4, 65, 'It rubs its snout on the ground to find and dig up food. It sometimes discovers hot springs.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/220.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (221, 'piloswine', 221, 100, 100, 80, 60, 60, 50, 11, 558, 'Because the long hair all over its body obscures its sight, it just keeps charging repeatedly.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/221.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (222, 'corsola', 222, 65, 55, 95, 65, 95, 35, 6, 50, 'It continuously sheds and grows. The tip of its head is prized as a treasure for its beauty.', 2, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/222.png', FALSE);
