INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (439, 'mime-jr', 439, 20, 25, 45, 70, 90, 60, 6, 130, 'It habitually mimics foes. Once mimicked, the foe cannot take its eyes off this Pokémon.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/439.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (440, 'happiny', 440, 100, 5, 5, 15, 65, 30, 6, 244, 'It loves round white things. It carries an egg-shaped rock in imitation of CHANSEY.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/440.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (441, 'chatot', 441, 76, 65, 45, 92, 42, 91, 5, 19, 'It can learn and speak human words. If they gather, they all learn the same saying.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/441.png', FALSE);
