INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (444, 'gabite', 444, 68, 90, 65, 50, 55, 82, 14, 560, 'There is a long-held belief that medicine made from its scales will heal even incurable illnesses.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/444.png', FALSE);
