INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (448, 'lucario', 448, 70, 110, 70, 115, 70, 90, 12, 540, 'It has the ability to sense the auras of all things. It understands human speech.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/448.png', FALSE);
