INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (487, 'giratina-altered', 487, 150, 100, 120, 100, 120, 90, 45, 7500, 'A Pokémon that is said to live in a world on the reverse side of ours. It appears in an ancient cemetery.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/487.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (488, 'cresselia', 488, 120, 70, 110, 75, 120, 85, 15, 856, 'Shiny particles are released from its wings like a veil. It is said to represent the crescent moon.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/488.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (489, 'phione', 489, 80, 80, 80, 80, 80, 80, 4, 31, 'It drifts in warm seas. It always returns to where it was born, no matter how far it may have drifted.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/489.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (490, 'manaphy', 490, 100, 100, 100, 100, 100, 100, 3, 14, 'Born on a cold seafloor, it will swim great distances to return to its birthplace.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/490.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (491, 'darkrai', 491, 70, 90, 90, 135, 90, 125, 15, 505, 'It can lull people to sleep and make them dream. It is active during nights of the new moon.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/491.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (492, 'shaymin-land', 492, 100, 100, 100, 100, 100, 100, 2, 21, 'It lives in flower patches and avoids detection by curling up to look like a flowering plant.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/492.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (493, 'arceus', 493, 120, 120, 120, 120, 120, 120, 32, 3200, 'It is described in mythology as the Pokémon that shaped the universe with its 1,000 arms.', 4, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/493.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (494, 'victini', 494, 100, 100, 100, 100, 100, 100, 4, 40, 'This Pokémon brings victory. It is said that Trainers with Victini always win, regardless of the type of encounter.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/494.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (495, 'snivy', 495, 45, 45, 55, 45, 55, 63, 6, 81, 'It is very intelligent and calm. Being exposed to lots of sunlight makes its movements swifter.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/495.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (496, 'servine', 496, 60, 60, 75, 60, 75, 83, 8, 160, 'It moves along the ground as if sliding. Its swift movements befuddle its foes, and it then attacks with a vine whip.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/496.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (497, 'serperior', 497, 75, 75, 95, 75, 95, 113, 33, 630, 'It can stop its opponents’ movements with just a glare. It takes in solar energy and boosts it internally.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/497.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (498, 'tepig', 498, 65, 63, 45, 45, 45, 45, 5, 99, 'It can deftly dodge its foe’s attacks while shooting fireballs from its nose. It roasts berries before it eats them.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/498.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (499, 'pignite', 499, 90, 93, 55, 70, 55, 55, 10, 555, 'When its internal fire flares up, its movements grow sharper and faster. When in trouble, it emits smoke.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/499.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (500, 'emboar', 500, 110, 123, 65, 100, 65, 65, 16, 1500, 'It can throw a fire punch by setting its fists on fire with its fiery chin. It cares deeply about its friends.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/500.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (501, 'oshawott', 501, 55, 55, 45, 63, 45, 45, 5, 59, 'It fights using the scalchop on its stomach. In response to an attack, it retaliates immediately by slashing.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/501.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (502, 'dewott', 502, 75, 75, 60, 83, 60, 60, 8, 245, 'Strict training is how it learns its flowing double-scalchop technique.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/502.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (503, 'samurott', 503, 95, 100, 85, 108, 70, 70, 15, 946, 'One swing of the sword incorporated in its armor can fell an opponent. A simple glare from one of them quiets everybody.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/503.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (504, 'patrat', 504, 45, 55, 39, 35, 39, 42, 5, 116, 'Using food stored in cheek pouches, they can keep watch for days. They use their tails to communicate with others.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/504.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (505, 'watchog', 505, 60, 85, 69, 60, 69, 77, 11, 270, 'When they see an enemy, their tails stand high, and they spit the seeds of berries stored in their cheek pouches.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/505.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (506, 'lillipup', 506, 45, 60, 45, 25, 45, 55, 4, 41, 'It faces strong opponents with great courage. But, when at a disadvantage in a fight, this intelligent Pokémon flees.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/506.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (507, 'herdier', 507, 65, 80, 65, 35, 65, 60, 9, 147, 'It has black, cape-like fur that is very hard and decreases the amount of damage it receives.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/507.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (508, 'stoutland', 508, 85, 110, 90, 45, 90, 80, 12, 610, 'It rescues people stranded by blizzards in the mountains. Its shaggy fur shields it from the cold.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/508.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (509, 'purrloin', 509, 41, 50, 37, 50, 37, 66, 4, 101, 'They steal from people for fun, but their victims can’t help but forgive them. Their deceptively cute act is perfect.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/509.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (510, 'liepard', 510, 64, 88, 50, 88, 50, 106, 11, 375, 'These Pokémon vanish and appear unexpectedly. Many Trainers are drawn to their beautiful form and fur.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/510.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (511, 'pansage', 511, 50, 53, 48, 53, 48, 64, 6, 105, 'This Pokémon dwells deep in the forest. Eating a leaf from its head whisks weariness away as if by magic.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/511.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (512, 'simisage', 512, 75, 98, 63, 98, 63, 101, 11, 305, 'Ill tempered, it fights by swinging its barbed tail around wildly. The leaf growing on its head is very bitter.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/512.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (513, 'pansear', 513, 50, 53, 48, 53, 48, 64, 6, 110, 'When it is angered, the temperature of its head tuft reaches 600° F. It uses its tuft to roast berries.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/513.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (514, 'simisear', 514, 75, 98, 63, 98, 63, 101, 10, 280, 'It loves sweets because they become energy for the fire burning inside its body.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/514.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (515, 'panpour', 515, 50, 53, 48, 53, 48, 64, 6, 135, 'The water stored inside the tuft on its head is full of nutrients. Plants that receive its water grow large.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/515.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (516, 'simipour', 516, 75, 98, 63, 98, 63, 101, 10, 290, 'The tuft on its head holds water. When the level runs low, it replenishes the tuft by siphoning up water with its tail.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/516.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (517, 'munna', 517, 76, 25, 45, 67, 55, 24, 6, 233, 'Munna always float in the air. People whose dreams are eaten by them forget what the dreams had been about.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/517.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (518, 'musharna', 518, 116, 55, 85, 107, 95, 29, 11, 605, 'The mist emanating from their foreheads is packed with the dreams of people and Pokémon.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/518.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (519, 'pidove', 519, 50, 55, 50, 36, 30, 43, 3, 21, 'Each follows its Trainer’s orders as best it can, but they sometimes fail to understand complicated commands.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/519.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (520, 'tranquill', 520, 62, 77, 62, 50, 42, 65, 6, 150, 'It can return to its Trainer’s location regardless of the distance separating them.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/520.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (521, 'unfezant', 521, 80, 115, 80, 65, 55, 93, 12, 290, 'Males swing their head plumage to threaten opponents. The females’ flying abilities surpass those of the males.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/521.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (522, 'blitzle', 522, 45, 60, 32, 50, 32, 76, 8, 298, 'When thunderclouds cover the sky, it will appear. It can catch lightning with its mane and store the electricity.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/522.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (523, 'zebstrika', 523, 75, 100, 63, 80, 63, 116, 16, 795, 'They have lightning-like movements. When Zebstrika run at full speed, the sound of thunder reverberates.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/523.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (524, 'roggenrola', 524, 55, 75, 85, 25, 25, 15, 4, 180, 'Its ear is hexagonal in shape. Compressed underground, its body is as hard as steel.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/524.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (525, 'boldore', 525, 70, 105, 105, 50, 40, 20, 9, 1020, 'When it overflows with power, the orange crystal on its body glows. It looks for underground water in caves.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/525.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (526, 'gigalith', 526, 85, 135, 130, 60, 80, 25, 17, 2600, 'Compressing the energy from its internal core lets it fire off an attack capable of blowing away a mountain.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/526.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (527, 'woobat', 527, 65, 45, 43, 55, 43, 72, 4, 21, 'Its habitat is dark forests and caves. It emits ultrasonic waves from its nose to learn about its surroundings.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/527.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (528, 'swoobat', 528, 67, 57, 55, 77, 55, 114, 9, 105, 'It emits sound waves of various frequencies from its nose, including some powerful enough to destroy rocks.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/528.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (529, 'drilbur', 529, 60, 85, 40, 30, 45, 68, 3, 85, 'It can dig through the ground at a speed of 30 mph. It could give a car running aboveground a good race.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/529.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (530, 'excadrill', 530, 110, 135, 60, 50, 65, 88, 7, 404, 'It can help in tunnel construction. Its drill has evolved into steel strong enough to bore through iron plates.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/530.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (531, 'audino', 531, 103, 60, 86, 60, 86, 50, 11, 310, 'It touches others with the feelers on its ears, using the sound of their heartbeats to tell how they are feeling.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/531.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (532, 'timburr', 532, 75, 80, 55, 25, 35, 35, 6, 125, 'It fights by swinging a piece of lumber around. It is close to evolving when it can handle the lumber without difficulty.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/532.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (533, 'gurdurr', 533, 85, 105, 85, 40, 50, 40, 12, 400, 'This Pokémon is so muscular and strongly built that even a group of wrestlers could not make it budge an inch.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/533.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (534, 'conkeldurr', 534, 105, 140, 95, 55, 65, 45, 14, 870, 'It is thought that Conkeldurr taught humans how to make concrete more than 2,000 years ago.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/534.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (535, 'tympole', 535, 50, 50, 40, 50, 40, 64, 5, 45, 'They warn others of danger by vibrating their cheeks to create a high-pitched sound.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/535.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (536, 'palpitoad', 536, 75, 65, 55, 65, 55, 69, 8, 170, 'When they vibrate the bumps on their heads, they can make waves in water or earthquake-like vibrations on land.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/536.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (537, 'seismitoad', 537, 105, 95, 75, 85, 75, 74, 15, 620, 'They shoot paralyzing liquid from their head bumps. They use vibration to hurt their opponents.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/537.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (538, 'throh', 538, 120, 100, 85, 30, 85, 45, 13, 555, 'When it tightens its belt, it becomes stronger. Wild Throh use vines to weave their own belts.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/538.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (539, 'sawk', 539, 75, 125, 75, 30, 75, 85, 14, 510, 'The sound of Sawk punching boulders and trees can be heard all the way from the mountains where they train.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/539.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (540, 'sewaddle', 540, 45, 53, 70, 40, 60, 42, 3, 25, 'Leavanny dress it in clothes they made for it when it hatched. It hides its head in its hood while it is sleeping.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/540.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (541, 'swadloon', 541, 55, 63, 90, 50, 80, 42, 5, 73, 'Forests where Swadloon live have superb foliage because the nutrients they make from fallen leaves nourish the plant life.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/541.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (542, 'leavanny', 542, 75, 103, 80, 70, 80, 92, 12, 205, 'Upon finding a small Pokémon, it weaves clothing for it from leaves, using the cutters on its arms and sticky silk.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/542.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (543, 'venipede', 543, 30, 45, 59, 30, 39, 57, 4, 53, 'Its bite injects a potent poison, enough to paralyze large bird Pokémon that try to prey on it.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/543.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (544, 'whirlipede', 544, 40, 55, 99, 40, 79, 47, 12, 585, 'Protected by a hard shell, it spins its body like a wheel and crashes furiously into its enemies.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/544.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (545, 'scolipede', 545, 60, 100, 89, 55, 69, 112, 25, 2005, 'With quick movements, it chases down its foes, attacking relentlessly with its horns until it prevails.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/545.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (546, 'cottonee', 546, 40, 27, 60, 37, 50, 66, 3, 6, 'When attacked, it escapes by shooting cotton from its body. The cotton serves as a decoy to distract the attacker.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/546.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (547, 'whimsicott', 547, 60, 67, 85, 77, 75, 116, 7, 66, 'Like the wind, it can slip through any gap, no matter how small. It leaves balls of white fluff behind.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/547.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (548, 'petilil', 548, 45, 35, 50, 70, 50, 30, 5, 66, 'The leaves on its head are very bitter. Eating one of these leaves is known to refresh a tired body.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/548.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (549, 'lilligant', 549, 70, 60, 75, 110, 75, 90, 11, 163, 'Even veteran Trainers face a challenge in getting its beautiful flower to bloom. This Pokémon is popular with celebrities.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/549.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (550, 'basculin-red-striped', 550, 70, 92, 65, 80, 55, 98, 10, 180, 'Red and blue Basculin get along so poorly, they’ll start fighting instantly. These Pokémon are very hostile.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/550.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (551, 'sandile', 551, 50, 72, 35, 35, 35, 65, 7, 152, 'They live buried in the sands of the desert. The sun-warmed sands prevent their body temperature from dropping.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/551.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (552, 'krokorok', 552, 60, 82, 45, 45, 45, 74, 10, 334, 'They live in groups of a few individuals. Protective membranes shield their eyes from sandstorms.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/552.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (553, 'krookodile', 553, 95, 117, 80, 65, 70, 92, 15, 963, 'They never allow prey to escape. Their jaws are so powerful, they can crush the body of an automobile.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/553.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (554, 'darumaka', 554, 70, 90, 45, 15, 45, 50, 6, 375, 'When its internal fire is burning, it cannot calm down and it runs around. When the fire diminishes, it falls asleep.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/554.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (555, 'darmanitan-standard', 555, 105, 140, 55, 30, 55, 95, 13, 929, 'Its internal fire burns at 2,500° F, making enough power that it can destroy a dump truck with one punch.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/555.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (556, 'maractus', 556, 75, 86, 67, 106, 67, 60, 10, 280, 'It uses an up-tempo song and dance to drive away the bird Pokémon that prey on its flower seeds.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/556.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (557, 'dwebble', 557, 50, 65, 85, 35, 35, 55, 3, 145, 'This Pokémon can easily melt holes in hard rocks with a liquid secreted from its mouth.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/557.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (558, 'crustle', 558, 70, 105, 125, 65, 75, 45, 14, 2000, 'Competing for territory, Crustle fight viciously. The one whose boulder is broken is the loser of the battle.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/558.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (559, 'scraggy', 559, 50, 75, 70, 35, 70, 48, 6, 118, 'Its skin has a rubbery elasticity, so it can reduce damage by defensively pulling its skin up to its neck.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/559.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (560, 'scrafty', 560, 65, 90, 115, 45, 115, 58, 11, 300, 'Groups of them beat up anything that enters their territory. Each can spit acidic liquid from its mouth.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/560.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (561, 'sigilyph', 561, 72, 58, 80, 103, 80, 97, 14, 140, 'They never vary the route they fly, because their memories of guarding an ancient city remain steadfast.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/561.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (562, 'yamask', 562, 38, 30, 85, 55, 65, 30, 5, 15, 'Each of them carries a mask that used to be its face when it was human. Sometimes they look at it and cry.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/562.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (563, 'cofagrigus', 563, 58, 50, 145, 95, 105, 30, 17, 765, 'It has been said that they swallow those who get too close and turn them into mummies. They like to eat gold nuggets.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/563.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (564, 'tirtouga', 564, 54, 78, 103, 53, 45, 22, 7, 165, 'Restored from a fossil, this Pokémon can dive to depths beyond half a mile.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/564.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (565, 'carracosta', 565, 74, 108, 133, 83, 65, 32, 12, 810, 'They can live both in the ocean and on land. A slap from one of them is enough to open a hole in the bottom of a tanker.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/565.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (566, 'archen', 566, 55, 112, 45, 74, 45, 70, 5, 95, 'Said to be an ancestor of bird Pokémon, they were unable to fly and moved about by hopping from one branch to another.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/566.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (567, 'archeops', 567, 75, 140, 65, 112, 65, 110, 14, 320, 'They are intelligent and will cooperate to catch prey. From the ground, they use a running start to take flight.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/567.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (568, 'trubbish', 568, 50, 50, 62, 40, 62, 65, 6, 310, 'Inhaling the gas they belch will make you sleep for a week. They prefer unsanitary places.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/568.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (569, 'garbodor', 569, 80, 95, 82, 60, 82, 75, 19, 1073, 'It clenches opponents with its left arm and finishes them off with foul-smelling poison gas belched from its mouth.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/569.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (570, 'zorua', 570, 40, 65, 40, 80, 40, 65, 7, 125, 'It changes into the forms of others to surprise them. Apparently, it often transforms into a silent child.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/570.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (571, 'zoroark', 571, 60, 105, 60, 120, 60, 105, 16, 811, 'Bonds between these Pokémon are very strong. It protects the safety of its pack by tricking its opponents.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/571.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (572, 'minccino', 572, 55, 50, 40, 40, 40, 75, 4, 58, 'They greet one another by rubbing each other with their tails, which are always kept well groomed and clean.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/572.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (573, 'cinccino', 573, 75, 95, 60, 65, 60, 115, 5, 75, 'Their white fur is coated in a special oil that makes it easy for them to deflect attacks.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/573.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (574, 'gothita', 574, 45, 30, 50, 55, 65, 45, 4, 58, 'Their ribbonlike feelers increase their psychic power. They are always staring at something.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/574.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (575, 'gothorita', 575, 60, 45, 70, 75, 85, 55, 7, 180, 'They use hypnosis to control people and Pokémon. Tales of Gothorita leading people astray are told in every corner.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/575.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (576, 'gothitelle', 576, 70, 55, 95, 95, 110, 65, 15, 440, 'Starry skies thousands of light-years away are visible in the space distorted by their intense psychic power.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/576.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (577, 'solosis', 577, 45, 30, 40, 105, 50, 20, 3, 10, 'They drive away attackers by unleashing psychic power. They can use telepathy to talk with others.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/577.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (578, 'duosion', 578, 65, 40, 50, 125, 60, 30, 6, 80, 'Since they have two divided brains, at times they suddenly try to take two different actions at once.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/578.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (579, 'reuniclus', 579, 110, 65, 75, 125, 85, 30, 10, 201, 'When Reuniclus shake hands, a network forms between their brains, increasing their psychic power.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/579.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (580, 'ducklett', 580, 62, 44, 50, 44, 50, 55, 5, 55, 'These bird Pokémon are excellent divers. They swim around in the water eating their favorite food--peat moss.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/580.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (581, 'swanna', 581, 75, 87, 63, 87, 63, 98, 13, 242, 'Swanna start to dance at dusk. The one dancing in the middle is the leader of the flock.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/581.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (582, 'vanillite', 582, 36, 50, 50, 65, 60, 44, 4, 57, 'The temperature of their breath is -58° F. They create snow crystals and make snow fall in the areas around them.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/582.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (583, 'vanillish', 583, 51, 65, 65, 80, 75, 59, 11, 410, 'Snowy mountains are this Pokémon’s habitat. During an ancient ice age, they moved to southern areas.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/583.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (584, 'vanilluxe', 584, 71, 95, 85, 110, 95, 79, 13, 575, 'Swallowing large amounts of water, they make snow clouds inside their bodies and attack their foes with violent blizzards.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/584.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (585, 'deerling', 585, 60, 60, 50, 40, 50, 75, 6, 195, 'The color and scent of their fur changes to match the mountain grass. When they sense hostility, they hide in the grass.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/585.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (586, 'sawsbuck', 586, 80, 100, 70, 60, 70, 95, 19, 925, 'They migrate according to the seasons. People can tell the season by looking at Sawsbuck’s horns.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/586.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (587, 'emolga', 587, 55, 75, 60, 75, 60, 103, 4, 50, 'The energy made in its cheeks’ electric pouches is stored inside its membrane and released while it is gliding.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/587.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (588, 'karrablast', 588, 50, 75, 45, 40, 45, 60, 5, 59, 'These mysterious Pokémon evolve when they receive electrical stimulation while they are in the same place as Shelmet.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/588.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (589, 'escavalier', 589, 70, 135, 105, 60, 105, 20, 10, 330, 'They fly around at high speed, striking with their pointed spears. Even when in trouble, they face opponents bravely.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/589.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (590, 'foongus', 590, 69, 55, 45, 55, 55, 15, 2, 10, 'It lures people in with its Poké Ball pattern, then releases poison spores. Why it resembles a Poké Ball is unknown.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/590.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (591, 'amoonguss', 591, 114, 85, 70, 85, 80, 30, 6, 105, 'It lures prey close by dancing and waving its arm caps, which resemble Poké Balls, in a swaying motion.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/591.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (592, 'frillish-male', 592, 55, 40, 50, 65, 85, 40, 12, 330, 'With its thin, veil-like arms wrapped around the body of its opponent, it sinks to the ocean floor.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/592.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (593, 'jellicent-male', 593, 100, 60, 70, 85, 105, 60, 22, 1350, 'The fate of the ships and crew that wander into Jellicent’s habitat: all sunken, all lost, all vanished.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/593.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (594, 'alomomola', 594, 165, 75, 80, 40, 45, 65, 12, 316, 'The special membrane enveloping Alomomola has the ability to heal wounds.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/594.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (595, 'joltik', 595, 50, 47, 50, 57, 50, 65, 1, 6, 'Joltik that live in cities have learned a technique for sucking electricity from the outlets in houses.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/595.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (596, 'galvantula', 596, 70, 77, 60, 97, 60, 108, 8, 143, 'When attacked, they create an electric barrier by spitting out many electrically charged threads.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/596.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (597, 'ferroseed', 597, 44, 50, 91, 24, 86, 10, 6, 188, 'When threatened, it attacks by shooting a barrage of spikes, which gives it a chance to escape by rolling away.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/597.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (598, 'ferrothorn', 598, 74, 94, 131, 54, 116, 20, 10, 1100, 'It fights by swinging around its three spiky feelers. A hit from these steel spikes can reduce a boulder to rubble.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/598.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (599, 'klink', 599, 40, 55, 70, 45, 60, 30, 3, 210, 'The two minigears that mesh together are predetermined. Each will rebound from other minigears without meshing.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/599.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (600, 'klang', 600, 60, 80, 95, 70, 85, 50, 6, 510, 'By changing the direction in which it rotates, it communicates its feelings to others. When angry, it rotates faster.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/600.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (601, 'klinklang', 601, 60, 100, 115, 70, 85, 90, 6, 810, 'The gear with the red core is rotated at high speed for a rapid energy charge.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/601.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (602, 'tynamo', 602, 35, 55, 40, 45, 40, 60, 2, 3, 'While one alone doesn’t have much power, a chain of many Tynamo can be as powerful as lightning.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/602.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (603, 'eelektrik', 603, 65, 85, 70, 75, 70, 40, 12, 220, 'They coil around foes and shock them with electricity-generating organs that seem simply to be circular patterns.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/603.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (604, 'eelektross', 604, 85, 115, 80, 105, 80, 50, 21, 805, 'They crawl out of the ocean using their arms. They will attack prey on shore and immediately drag it into the ocean.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/604.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (605, 'elgyem', 605, 55, 55, 55, 85, 55, 30, 5, 90, 'It uses its strong psychic power to squeeze its opponent’s brain, causing unendurable headaches.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/605.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (606, 'beheeyem', 606, 75, 75, 75, 125, 95, 40, 10, 345, 'It can manipulate an opponent’s memory. Apparently, it communicates by flashing its three different-colored fingers.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/606.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (607, 'litwick', 607, 50, 30, 55, 65, 55, 20, 3, 31, 'Litwick shines a light that absorbs the life energy of people and Pokémon, which becomes the fuel that it burns.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/607.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (608, 'lampent', 608, 60, 40, 60, 95, 60, 55, 6, 130, 'This ominous Pokémon is feared. Through cities it wanders, searching for the spirits of the fallen.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/608.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (609, 'chandelure', 609, 60, 55, 90, 145, 90, 80, 10, 343, 'It absorbs a spirit, which it then burns. By waving the flames on its arms, it puts its foes into a hypnotic trance.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/609.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (610, 'axew', 610, 46, 87, 60, 30, 40, 57, 6, 180, 'They use their tusks to crush the berries they eat. Repeated regrowth makes their tusks strong and sharp.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/610.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (611, 'fraxure', 611, 66, 117, 70, 40, 50, 67, 10, 360, 'Since a broken tusk will not grow back, they diligently sharpen their tusks on river rocks after they’ve been fighting.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/611.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (612, 'haxorus', 612, 76, 147, 90, 60, 70, 97, 18, 1055, 'They are kind but can be relentless when defending territory. They challenge foes with tusks that can cut steel.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/612.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (613, 'cubchoo', 613, 55, 70, 40, 60, 40, 40, 5, 85, 'When it is not feeling well, its mucus gets watery and the power of its Ice-type moves decreases.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/613.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (614, 'beartic', 614, 95, 130, 80, 70, 80, 50, 26, 2600, 'It can make its breath freeze at will. Very able in the water, it swims around in northern seas and catches prey.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/614.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (615, 'cryogonal', 615, 80, 50, 50, 95, 135, 105, 11, 1480, 'When its body temperature goes up, it turns into steam and vanishes. When its temperature lowers, it returns to ice.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/615.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (616, 'shelmet', 616, 50, 40, 85, 40, 65, 25, 4, 77, 'When attacked, it defends itself by closing the lid of its shell. It can spit a sticky, poisonous liquid.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/616.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (617, 'accelgor', 617, 80, 70, 40, 100, 60, 145, 8, 253, 'When its body dries out, it weakens. So, to prevent dehydration, it wraps itself in many layers of thin membrane.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/617.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (618, 'stunfisk', 618, 109, 66, 84, 81, 99, 32, 7, 110, 'Its skin is very hard, so it is unhurt even if stepped on by sumo wrestlers. It smiles when transmitting electricity.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/618.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (619, 'mienfoo', 619, 45, 85, 50, 55, 50, 65, 9, 200, 'In fights, they dominate with onslaughts of flowing, continuous attacks. With their sharp claws, they cut enemies.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/619.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (620, 'mienshao', 620, 65, 125, 60, 95, 60, 105, 14, 355, 'It wields the fur on its arms like a whip. Its arm attacks come with such rapidity that they cannot even be seen.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/620.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (621, 'druddigon', 621, 77, 120, 90, 60, 90, 48, 16, 1390, 'It warms its body by absorbing sunlight with its wings. When its body temperature falls, it can no longer move.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/621.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (622, 'golett', 622, 59, 74, 50, 35, 50, 35, 10, 920, 'The energy that burns inside it enables it to move, but no one has yet been able to identify this energy.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/622.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (623, 'golurk', 623, 89, 124, 80, 55, 80, 55, 28, 3300, 'It flies across the sky at Mach speeds. Removing the seal on its chest makes its internal energy go out of control.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/623.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (624, 'pawniard', 624, 45, 85, 70, 40, 40, 60, 5, 102, 'Blades comprise this Pokémon’s entire body. If battling dulls the blades, it sharpens them on stones by the river.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/624.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (625, 'bisharp', 625, 65, 125, 100, 60, 70, 70, 16, 700, 'It leads a group of Pawniard. It battles to become the boss, but will be driven from the group if it loses.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/625.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (626, 'bouffalant', 626, 95, 110, 95, 40, 95, 55, 16, 946, 'Their fluffy fur absorbs damage, even if they strike foes with a fierce headbutt.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/626.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (627, 'rufflet', 627, 70, 83, 50, 37, 50, 60, 5, 105, 'They crush berries with their talons. They bravely stand up to any opponent, no matter how strong it is.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/627.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (628, 'braviary', 628, 100, 123, 75, 57, 75, 80, 15, 410, 'They fight for their friends without any thought about danger to themselves. One can carry a car while flying.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/628.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (629, 'vullaby', 629, 70, 55, 75, 45, 65, 60, 5, 90, 'Their wings are too tiny to allow them to fly. They guard their posteriors with bones that were gathered by Mandibuzz.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/629.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (630, 'mandibuzz', 630, 110, 65, 105, 55, 95, 80, 12, 395, 'It makes a nest out of bones it finds. It grabs weakened prey in its talons and hauls it to its nest of bones.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/630.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (631, 'heatmor', 631, 85, 97, 66, 105, 66, 65, 14, 580, 'It breathes through a hole in its tail while it burns with an internal fire. Durant is its prey.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/631.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (632, 'durant', 632, 58, 109, 112, 48, 48, 109, 3, 330, 'They attack in groups, covering themselves in steel armor to protect themselves from Heatmor.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/632.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (633, 'deino', 633, 52, 65, 50, 45, 50, 38, 8, 173, 'It tends to bite everything, and it is not a picky eater. Approaching it carelessly is dangerous.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/633.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (634, 'zweilous', 634, 72, 85, 70, 65, 70, 58, 14, 500, 'After it has eaten up all the food in its territory, it moves to another area. Its two heads do not get along.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/634.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (635, 'hydreigon', 635, 92, 105, 90, 125, 90, 98, 18, 1600, 'This brutal Pokémon travels the skies on its six wings. Anything that moves seems like a foe to it, triggering its attack.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/635.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (636, 'larvesta', 636, 55, 85, 55, 50, 55, 60, 11, 288, 'This Pokémon was believed to have been born from the sun. When it evolves, its entire body is engulfed in flames.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/636.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (637, 'volcarona', 637, 85, 60, 65, 135, 105, 100, 16, 460, 'When volcanic ash darkened the atmosphere, it is said that Volcarona’s fire provided a replacement for the sun.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/637.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (638, 'cobalion', 638, 91, 90, 129, 90, 72, 108, 21, 2500, 'This legendary Pokémon battled against humans to protect Pokémon. Its personality is calm and composed.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/638.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (639, 'terrakion', 639, 91, 129, 90, 72, 90, 108, 19, 2600, 'This Pokémon came to the defense of Pokémon that had lost their homes in a war among humans.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/639.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (640, 'virizion', 640, 91, 90, 72, 90, 129, 108, 20, 2000, 'This Pokémon fought humans in order to protect its friends. Legends about it continue to be passed down.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/640.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (641, 'tornadus-incarnate', 641, 79, 115, 70, 125, 80, 111, 15, 630, 'The lower half of its body is wrapped in a cloud of energy. It zooms through the sky at 200 mph.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/641.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (642, 'thundurus-incarnate', 642, 79, 115, 70, 125, 80, 111, 15, 610, 'Countless charred remains mar the landscape of places through which Thundurus has passed.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/642.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (643, 'reshiram', 643, 100, 120, 100, 150, 120, 90, 32, 3300, 'This Pokémon appears in legends. It sends flames into the air from its tail, burning up everything around it.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/643.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (644, 'zekrom', 644, 100, 150, 120, 120, 100, 90, 29, 3450, 'Concealing itself in lightning clouds, it flies throughout the Unova region. It creates electricity in its tail.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/644.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (645, 'landorus-incarnate', 645, 89, 125, 90, 115, 80, 101, 15, 680, 'Lands visited by Landorus grant such bountiful crops that it has been hailed as “The Guardian of the Fields.”', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/645.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (646, 'kyurem', 646, 125, 130, 90, 130, 90, 95, 30, 3250, 'It generates a powerful, freezing energy inside itself, but its body became frozen when the energy leaked out.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/646.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (647, 'keldeo-ordinary', 647, 91, 72, 90, 129, 90, 108, 14, 485, 'By blasting water from its hooves, it can glide across water. It excels at using leg moves while battling.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/647.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (648, 'meloetta-aria', 648, 100, 77, 77, 128, 128, 90, 6, 65, 'Its melodies are sung with a special vocalization method that can control the feelings of those who hear it.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/648.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (649, 'genesect', 649, 71, 120, 95, 120, 95, 99, 15, 825, 'Over 300 million years ago, it was feared as the strongest of hunters. It has been modified by Team Plasma.', 5, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/649.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (650, 'chespin', 650, 56, 61, 65, 48, 45, 38, 4, 90, 'The quills on its head are usually soft. When it flexes them, the points become so hard and sharp that they can pierce rock.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/650.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (651, 'quilladin', 651, 61, 78, 95, 56, 58, 57, 7, 290, 'It relies on its sturdy shell to deflect predators’ attacks. It counterattacks with its sharp quills.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/651.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (652, 'chesnaught', 652, 88, 107, 122, 74, 75, 64, 16, 900, 'Its Tackle is forceful enough to flip a 50-ton tank. It shields its allies from danger with its own body.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/652.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (653, 'fennekin', 653, 40, 45, 40, 62, 60, 60, 4, 94, 'Eating a twig fills it with energy, and its roomy ears give vent to air hotter than 390 degrees Fahrenheit.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/653.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (654, 'braixen', 654, 59, 59, 58, 90, 70, 73, 10, 145, 'It has a twig stuck in its tail. With friction from its tail fur, it sets the twig on fire and launches into battle.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/654.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (655, 'delphox', 655, 75, 69, 72, 114, 100, 104, 15, 390, 'It gazes into the flame at the tip of its branch to achieve a focused state, which allows it to see into the future.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/655.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (656, 'froakie', 656, 41, 56, 40, 62, 44, 71, 3, 70, 'It secretes flexible bubbles from its chest and back. The bubbles reduce the damage it would otherwise take when attacked.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/656.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (657, 'frogadier', 657, 54, 63, 52, 83, 56, 97, 6, 109, 'It can throw bubble-covered pebbles with precise control, hitting empty cans up to a hundred feet away.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/657.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (658, 'greninja', 658, 72, 95, 67, 103, 71, 122, 15, 400, 'It creates throwing stars out of compressed water. When it spins them and throws them at high speed, these stars can split metal in two.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/658.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (659, 'bunnelby', 659, 38, 36, 38, 32, 36, 57, 4, 50, 'They use their large ears to dig burrows. They will dig the whole night through.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/659.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (660, 'diggersby', 660, 85, 56, 77, 50, 77, 78, 10, 424, 'With their powerful ears, they can heft boulders of a ton or more with ease. They can be a big help at construction sites.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/660.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (661, 'fletchling', 661, 45, 50, 43, 40, 38, 62, 3, 17, 'These friendly Pokémon send signals to one another with beautiful chirps and tail-feather movements.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/661.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (662, 'fletchinder', 662, 62, 73, 55, 56, 52, 84, 7, 160, 'From its beak, it expels embers that set the tall grass on fire. Then it pounces on the bewildered prey that pop out of the grass.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/662.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (663, 'talonflame', 663, 78, 81, 71, 74, 69, 126, 12, 245, 'In the fever of an exciting battle, it showers embers from the gaps between its feathers and takes to the air.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/663.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (664, 'scatterbug', 664, 38, 35, 40, 27, 25, 35, 3, 25, 'When under attack from bird Pokémon, it spews a poisonous black powder that causes paralysis on contact.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/664.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (665, 'spewpa', 665, 45, 22, 60, 27, 30, 29, 3, 84, 'It lives hidden within thicket shadows. When predators attack, it quickly bristles the fur covering its body in an effort to threaten them.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/665.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (666, 'vivillon', 666, 80, 52, 50, 90, 50, 89, 12, 170, 'Vivillon with many different patterns are found all over the world. These patterns are affected by the climate of their habitat.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/666.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (667, 'litleo', 667, 62, 50, 58, 73, 54, 72, 6, 135, 'The stronger the opponent it faces, the more heat surges from its mane and the more power flows through its body.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/667.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (668, 'pyroar-male', 668, 86, 68, 72, 109, 66, 106, 15, 815, 'The male with the largest mane of fire is the leader of the pride.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/668.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (669, 'flabebe', 669, 44, 38, 39, 61, 79, 42, 1, 1, 'It draws out and controls the hidden power of flowers. The flower Flabébé holds is most likely part of its body.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/669.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (670, 'floette', 670, 54, 45, 47, 75, 98, 52, 2, 9, 'It flutters around fields of flowers and cares for flowers that are starting to wilt. It draws out the hidden power of flowers to battle.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/670.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (671, 'florges', 671, 78, 65, 68, 112, 154, 75, 11, 100, 'It claims exquisite flower gardens as its territory, and it obtains power from basking in the energy emitted by flowering plants.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/671.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (672, 'skiddo', 672, 66, 65, 48, 62, 57, 52, 9, 310, 'Thought to be one of the first Pokémon to live in harmony with humans, it has a placid disposition.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/672.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (673, 'gogoat', 673, 123, 100, 62, 97, 81, 68, 17, 910, 'It can tell how its Trainer is feeling by subtle shifts in the grip on its horns. This empathic sense lets them run as if one being.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/673.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (674, 'pancham', 674, 67, 82, 62, 46, 48, 43, 6, 80, 'It does its best to be taken seriously by its enemies, but its glare is not sufficiently intimidating. Chewing on a leaf is its trademark.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/674.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (675, 'pangoro', 675, 95, 124, 78, 69, 71, 58, 21, 1360, 'Although it possesses a violent temperament, it won’t put up with bullying. It uses the leaf in its mouth to sense the movements of its enemies.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/675.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (676, 'furfrou', 676, 75, 80, 60, 65, 90, 102, 12, 280, 'Trimming its fluffy fur not only makes it more elegant but also increases the swiftness of its movements.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/676.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (677, 'espurr', 677, 62, 48, 54, 63, 60, 68, 3, 35, 'The organ that emits its intense psychic power is sheltered by its ears to keep power from leaking out.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/677.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (678, 'meowstic-male', 678, 74, 48, 76, 83, 81, 104, 6, 85, 'When in danger, it raises its ears and releases enough psychic power to grind a 10-ton truck into dust.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/678.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (679, 'honedge', 679, 45, 80, 100, 35, 37, 28, 8, 20, 'Apparently this Pokémon is born when a departed spirit inhabits a sword. It attaches itself to people and drinks their life force.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/679.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (680, 'doublade', 680, 59, 110, 150, 45, 49, 35, 8, 45, 'When Honedge evolves, it divides into two swords, which cooperate via telepathy to coordinate attacks and slash their enemies to ribbons.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/680.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (681, 'aegislash-shield', 681, 60, 50, 140, 50, 140, 60, 17, 530, 'Generations of kings were attended by these Pokémon, which used their spectral power to manipulate and control people and Pokémon.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/681.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (682, 'spritzee', 682, 78, 52, 60, 63, 65, 23, 2, 5, 'It emits a scent that enraptures those who smell it. This fragrance changes depending on what it has eaten.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/682.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (683, 'aromatisse', 683, 101, 72, 72, 99, 89, 29, 8, 155, 'It devises various scents, pleasant and unpleasant, and emits scents that its enemies dislike in order to gain an edge in battle.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/683.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (684, 'swirlix', 684, 62, 48, 66, 59, 57, 49, 4, 35, 'To entangle its opponents in battle, it extrudes white threads as sweet and sticky as cotton candy.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/684.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (685, 'slurpuff', 685, 82, 80, 86, 85, 75, 72, 8, 50, 'It can distinguish the faintest of scents. It puts its sensitive sense of smell to use by helping pastry chefs in their work.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/685.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (686, 'inkay', 686, 53, 54, 53, 37, 46, 45, 4, 35, 'Opponents who stare at the flashing of the light-emitting spots on its body become dazed and lose their will to fight.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/686.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (687, 'malamar', 687, 86, 92, 88, 68, 75, 73, 15, 470, 'It wields the most compelling hypnotic powers of any Pokémon, and it forces others to do whatever it wants.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/687.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (688, 'binacle', 688, 42, 52, 67, 39, 56, 50, 5, 310, 'Two Binacle live together on one rock. When they fight, one of them will move to a different rock.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/688.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (689, 'barbaracle', 689, 72, 105, 115, 54, 86, 68, 13, 960, 'When they evolve, two Binacle multiply into seven. They fight with the power of seven Binacle.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/689.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (690, 'skrelp', 690, 50, 60, 60, 60, 60, 30, 5, 73, 'Camouflaged as rotten kelp, they spray liquid poison on prey that approaches unawares and then finish it off.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/690.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (691, 'dragalge', 691, 65, 75, 90, 97, 123, 44, 18, 815, 'Their poison is strong enough to eat through the hull of a tanker, and they spit it indiscriminately at anything that enters their territory.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/691.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (692, 'clauncher', 692, 50, 53, 62, 58, 63, 44, 5, 83, 'They knock down flying prey by firing compressed water from their massive claws like shooting a pistol.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/692.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (693, 'clawitzer', 693, 71, 73, 88, 120, 89, 59, 13, 353, 'Their enormous claws launch cannonballs of water powerful enough to pierce tanker hulls.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/693.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (694, 'helioptile', 694, 44, 38, 33, 61, 43, 70, 5, 60, 'They make their home in deserts. They can generate their energy from basking in the sun, so eating food is not a requirement.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/694.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (695, 'heliolisk', 695, 62, 55, 52, 109, 94, 109, 10, 210, 'They flare their frills and generate energy. A single Heliolisk can generate sufficient electricity to power a skyscraper.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/695.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (696, 'tyrunt', 696, 58, 89, 77, 45, 45, 48, 8, 260, 'This Pokémon was restored from a fossil. If something happens that it doesn’t like, it throws a tantrum and runs wild.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/696.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (697, 'tyrantrum', 697, 82, 121, 119, 69, 59, 71, 25, 2700, 'Thanks to its gargantuan jaws, which could shred thick metal plates as if they were paper, it was invincible in the ancient world it once inhabited.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/697.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (698, 'amaura', 698, 77, 59, 50, 67, 63, 46, 13, 252, 'This ancient Pokémon was restored from part of its body that had been frozen in ice for over 100 million years.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/698.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (699, 'aurorus', 699, 123, 77, 72, 99, 92, 58, 27, 2250, 'The diamond-shaped crystals on its body expel air as cold as -240 degrees Fahrenheit, surrounding its enemies and encasing them in ice.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/699.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (700, 'sylveon', 700, 95, 65, 65, 110, 130, 60, 10, 235, 'It sends a soothing aura from its ribbonlike feelers to calm fights.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/700.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (701, 'hawlucha', 701, 78, 92, 75, 74, 63, 118, 8, 215, 'Although its body is small, its proficient fighting skills enable it to keep up with big bruisers like Machamp and Hariyama.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/701.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (702, 'dedenne', 702, 67, 58, 57, 81, 67, 101, 2, 22, 'Its whiskers serve as antennas. By sending and receiving electrical waves, it can communicate with others over vast distances.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/702.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (703, 'carbink', 703, 50, 50, 150, 50, 150, 50, 3, 57, 'Born from the temperatures and pressures deep underground, it fires beams from the stone in its head.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/703.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (704, 'goomy', 704, 45, 50, 35, 55, 75, 40, 3, 28, 'The weakest Dragon-type Pokémon, it lives in damp, shady places, so its body doesn’t dry out.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/704.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (705, 'sliggoo', 705, 68, 75, 53, 83, 113, 60, 8, 175, 'It drives away opponents by excreting a sticky liquid that can dissolve anything. Its eyes devolved, so it can’t see anything.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/705.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (706, 'goodra', 706, 90, 100, 70, 110, 150, 80, 20, 1505, 'This very friendly Dragon-type Pokémon will hug its beloved Trainer, leaving that Trainer covered in sticky slime.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/706.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (707, 'klefki', 707, 57, 80, 91, 80, 87, 75, 2, 30, 'These key collectors threaten any attackers by fiercely jingling their keys at them.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/707.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (708, 'phantump', 708, 43, 70, 48, 50, 60, 38, 4, 70, 'These Pokémon are created when spirits possess rotten tree stumps. They prefer to live in abandoned forests.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/708.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (709, 'trevenant', 709, 85, 110, 76, 65, 82, 56, 15, 710, 'It can control trees at will. It will trap people who harm the forest, so they can never leave.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/709.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (710, 'pumpkaboo-average', 710, 49, 66, 70, 44, 55, 51, 4, 50, 'The pumpkin body is inhabited by a spirit trapped in this world. As the sun sets, it becomes restless and active.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/710.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (711, 'gourgeist-average', 711, 65, 90, 122, 58, 75, 84, 9, 125, 'Singing in eerie voices, they wander town streets on the night of the new moon. Anyone who hears their song is cursed.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/711.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (712, 'bergmite', 712, 55, 69, 85, 32, 35, 28, 10, 995, 'It blocks opponents’ attacks with the ice that shields its body. It uses cold air to repair any cracks with new ice.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/712.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (713, 'avalugg', 713, 95, 117, 184, 44, 46, 28, 20, 5050, 'Its ice-covered body is as hard as steel. Its cumbersome frame crushes anything that stands in its way.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/713.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (714, 'noibat', 714, 40, 30, 35, 45, 40, 55, 5, 80, 'They live in pitch-black caves. Their enormous ears can emit ultrasonic waves of 200,000 hertz.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/714.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (715, 'noivern', 715, 85, 70, 80, 97, 80, 123, 15, 850, 'They fly around on moonless nights and attack careless prey. Nothing can beat them in a battle in the dark.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/715.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (716, 'xerneas', 716, 126, 131, 95, 131, 98, 99, 30, 2150, 'Legends say it can share eternal life. It slept for a thousand years in the form of a tree before its revival.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/716.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (717, 'yveltal', 717, 126, 131, 95, 131, 98, 99, 58, 2030, 'When this legendary Pokémon’s wings and tail feathers spread wide and glow red, it absorbs the life force of living creatures.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/717.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (718, 'zygarde-50', 718, 108, 100, 121, 81, 95, 95, 50, 3050, 'When the Kalos region’s ecosystem falls into disarray, it appears and reveals its secret power.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/718.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (719, 'diancie', 719, 50, 100, 150, 100, 150, 50, 7, 88, 'A sudden transformation of Carbink, its pink, glimmering body is said to be the loveliest sight in the whole world.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/719.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (720, 'hoopa', 720, 80, 110, 60, 150, 130, 70, 5, 90, 'This troublemaker sends anything and everything to faraway places using its loop, which can warp space.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/720.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (721, 'volcanion', 721, 80, 110, 120, 130, 90, 70, 17, 1950, 'It lets out billows of steam and disappears into the dense fog. It’s said to live in mountains where humans do not tread.', 6, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/721.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (722, 'rowlet', 722, 68, 55, 55, 50, 50, 42, 3, 15, 'This wary Pokémon uses photosynthesis to store up energy during the day, while becoming active at night.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/722.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (723, 'dartrix', 723, 78, 75, 75, 70, 70, 52, 7, 160, 'A bit of a dandy, it spends its free time preening its wings. Its preoccupation with any dirt on its plumage can leave it unable to battle.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/723.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (724, 'decidueye', 724, 78, 107, 75, 100, 100, 70, 16, 366, 'It fires arrow quills from its wings with such precision, they can pierce a pebble at distances over a hundred yards.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/724.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (725, 'litten', 725, 45, 65, 40, 60, 40, 70, 4, 43, 'While grooming itself, it builds up fur inside its stomach. It sets the fur alight and spews fiery attacks, which change based on how it coughs.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/725.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (726, 'torracat', 726, 65, 85, 50, 80, 50, 90, 7, 250, 'At its throat, it bears a bell of fire. The bell rings brightly whenever this Pokémon spits fire.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/726.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (727, 'incineroar', 727, 95, 115, 90, 80, 90, 60, 18, 830, 'This Pokémon has a violent, selfish disposition. If it’s not in the mood to listen, it will ignore its Trainer’s orders with complete nonchalance.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/727.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (728, 'popplio', 728, 50, 54, 54, 66, 56, 40, 4, 75, 'This Pokémon snorts body fluids from its nose, blowing balloons to smash into its foes. It’s famous for being a hard worker.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/728.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (729, 'brionne', 729, 60, 69, 69, 91, 81, 50, 6, 175, 'A skillful dancer, it creates a sequence of water balloons as it dances, and briskly bombards its enemies.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/729.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (730, 'primarina', 730, 80, 74, 74, 126, 116, 60, 18, 440, 'It controls its water balloons with song. The melody is learned from others of its kind and is passed down from one generation to the next.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/730.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (731, 'pikipek', 731, 35, 75, 30, 30, 30, 65, 3, 12, 'It can peck at a rate of 16 times a second to drill holes in trees. It uses the holes for food storage and for nesting.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/731.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (732, 'trumbeak', 732, 55, 85, 50, 40, 50, 75, 6, 148, 'It eats berries and stores their seeds in its beak. When it encounters enemies or prey, it fires off all the seeds in a burst.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/732.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (733, 'toucannon', 733, 80, 120, 75, 75, 75, 60, 11, 260, 'When it battles, its beak heats up. The temperature can easily exceed 212 degrees Fahrenheit, causing severe burns when it hits.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/733.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (734, 'yungoos', 734, 48, 70, 30, 30, 30, 45, 4, 60, 'With its sharp fangs, it will bite anything. It did not originally live in Alola but was imported from another region.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/734.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (735, 'gumshoos', 735, 88, 110, 60, 55, 60, 45, 7, 142, 'When it finds a trace of its prey, it patiently stakes out the location...but it’s always snoozing by nightfall.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/735.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (736, 'grubbin', 736, 47, 62, 45, 55, 45, 46, 4, 44, 'Its strong jaw enables it to scrape trees and slurp out the sap. It normally lives underground.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/736.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (737, 'charjabug', 737, 57, 82, 95, 55, 75, 36, 5, 105, 'Its body is capable of storing electricity. On camping trips, people are grateful to have one around.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/737.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (738, 'vikavolt', 738, 77, 70, 90, 145, 75, 43, 15, 450, 'It zips around, on sharp lookout for an opening. It concentrates electrical energy within its large jaws and uses it to zap its enemies.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/738.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (739, 'crabrawler', 739, 47, 82, 57, 42, 47, 63, 6, 70, 'While guarding its weak points with its pincers, it looks for an opening and unleashes punches. When it loses, it foams at the mouth and faints.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/739.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (740, 'crabominable', 740, 97, 132, 77, 62, 67, 43, 17, 1800, 'It aimed for the top but got lost and ended up on a snowy mountain. Being forced to endure the cold, this Pokémon evolved and grew fur.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/740.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (741, 'oricorio-baile', 741, 75, 70, 70, 98, 70, 93, 6, 34, 'It beats its wings together to create fire. As it moves in the steps of its beautiful dance, it bathes opponents in intense flames.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/741.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (742, 'cutiefly', 742, 40, 45, 40, 55, 40, 84, 1, 2, 'It feeds on the nectar and pollen of flowers. Because it’s able to sense auras, it can identify which flowers are about to bloom.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/742.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (743, 'ribombee', 743, 60, 55, 60, 95, 70, 124, 2, 5, 'It rolls up pollen into puffs. It makes many different varieties, some used as food and others used in battle.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/743.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (744, 'rockruff', 744, 45, 65, 40, 30, 40, 60, 5, 92, 'It’s considered to be a good Pokémon for beginners because of its friendliness, but its disposition grows rougher as it grows up.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/744.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (745, 'lycanroc-midday', 745, 75, 115, 65, 55, 65, 112, 8, 250, 'Its quick movements confuse its enemies. Well equipped with claws and fangs, it also uses the sharp rocks in its mane as weapons.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/745.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (746, 'wishiwashi-solo', 746, 45, 20, 20, 25, 25, 40, 2, 3, 'When it’s in trouble, its eyes moisten and begin to shine. The shining light attracts its comrades, and they stand together against their enemies.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/746.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (747, 'mareanie', 747, 50, 53, 62, 43, 52, 45, 4, 80, 'It plunges the poison spike on its head into its prey. When the prey has weakened, Mareanie deals the finishing blow with its 10 tentacles.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/747.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (748, 'toxapex', 748, 50, 63, 152, 53, 142, 35, 7, 145, 'Toxapex crawls along the ocean floor on its 12 legs. It leaves a trail of Corsola bits scattered in its wake.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/748.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (749, 'mudbray', 749, 70, 100, 70, 45, 55, 45, 10, 1100, 'The mud stuck to Mudbray’s hooves enhances its grip and its powerful running gait.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/749.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (750, 'mudsdale', 750, 100, 125, 100, 55, 85, 35, 25, 9200, 'It spits a mud that provides resistance to both wind and rain, so the walls of old houses were often coated with it.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/750.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (751, 'dewpider', 751, 38, 40, 52, 40, 72, 27, 3, 40, 'It crawls onto the land in search of food. Its water bubble allows it to breathe and protects its soft head.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/751.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (752, 'araquanid', 752, 68, 70, 92, 50, 132, 42, 18, 820, 'It delivers headbutts with the water bubble on its head. Small Pokémon get sucked into the bubble, where they drown.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/752.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (753, 'fomantis', 753, 40, 55, 35, 50, 35, 35, 3, 15, 'During the day, it sleeps and soaks up light. When night falls, it walks around looking for a safer place to sleep.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/753.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (754, 'lurantis', 754, 70, 105, 90, 80, 90, 45, 9, 185, 'It requires a lot of effort to maintain Lurantis’s vivid coloring, but some collectors enjoy this work and treat it as their hobby.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/754.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (755, 'morelull', 755, 40, 35, 55, 65, 75, 15, 2, 15, 'It scatters spores that flicker and glow. Anyone seeing these lights falls into a deep slumber.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/755.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (756, 'shiinotic', 756, 60, 45, 80, 90, 100, 30, 10, 115, 'Forests where Shiinotic live are treacherous to enter at night. People confused by its strange lights can never find their way home again.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/756.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (757, 'salandit', 757, 48, 44, 40, 71, 40, 77, 6, 48, 'It burns its bodily fluids to create a poisonous gas. When its enemies become disoriented from inhaling the gas, it attacks them.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/757.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (758, 'salazzle', 758, 68, 64, 60, 111, 60, 117, 12, 222, 'For some reason, only females have been found. It creates a reverse harem of male Salandit that it lives with.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/758.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (759, 'stufful', 759, 70, 75, 50, 45, 50, 50, 5, 68, 'Despite its adorable appearance, when it gets angry and flails about, its arms and legs could knock a pro wrestler sprawling.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/759.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (760, 'bewear', 760, 120, 125, 80, 55, 60, 60, 21, 1350, 'This immensely dangerous Pokémon possesses overwhelming physical strength. Its habitat is generally off-limits.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/760.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (761, 'bounsweet', 761, 42, 30, 38, 30, 38, 32, 3, 32, 'A delectable aroma pours from its body. They are often swallowed whole by Toucannon lured by that wafting deliciousness.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/761.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (762, 'steenee', 762, 52, 40, 48, 40, 48, 62, 7, 82, 'The sepals on its head developed to protect its body. These are quite hard, so even if pecked by bird Pokémon, this Pokémon is totally fine.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/762.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (763, 'tsareena', 763, 72, 120, 98, 50, 98, 72, 12, 214, 'Its long, striking legs aren’t just for show but to be used to kick with skill. In victory, it shows off by kicking the defeated, laughing boisterously.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/763.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (764, 'comfey', 764, 51, 52, 90, 82, 110, 100, 1, 3, 'It attaches flowers to its highly nutritious vine. This revitalizes the flowers, and they give off an aromatic scent.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/764.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (765, 'oranguru', 765, 90, 60, 80, 90, 110, 60, 15, 760, 'Known for its extreme intelligence, this Pokémon will look down on inexperienced Trainers, so it’s best suited to veteran Trainers.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/765.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (766, 'passimian', 766, 100, 120, 90, 40, 60, 80, 20, 828, 'They form groups of roughly 20 individuals. Their mutual bond is remarkable—they will never let down a comrade.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/766.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (767, 'wimpod', 767, 25, 35, 40, 20, 30, 80, 5, 120, 'This Pokémon is a coward. As it desperately dashes off, the flailing of its many legs leaves a sparkling clean path in its wake.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/767.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (768, 'golisopod', 768, 75, 125, 140, 60, 90, 40, 20, 1080, 'With a flashing slash of its giant sharp claws, it cleaves seawater—or even air—right in two.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/768.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (769, 'sandygast', 769, 55, 55, 80, 70, 45, 15, 5, 700, 'Born from a sand mound playfully built by a child, this Pokémon embodies the grudges of the departed.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/769.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (770, 'palossand', 770, 85, 75, 110, 100, 75, 35, 13, 2500, 'Possessed people controlled by this Pokémon transformed its sand mound into a castle. As it evolved, its power to curse grew ever stronger.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/770.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (771, 'pyukumuku', 771, 55, 60, 130, 30, 130, 5, 3, 12, 'It’s covered in a slime that keeps its skin moist, allowing it to stay on land for days without drying up.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/771.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (772, 'type-null', 772, 95, 95, 95, 95, 95, 59, 19, 1205, 'The heavy control mask it wears suppresses its intrinsic capabilities. This Pokémon has some hidden special power.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/772.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (773, 'silvally', 773, 95, 95, 95, 95, 95, 95, 23, 1005, 'Its trust in its partner is what awakens it. This Pokémon is capable of changing its type, a flexibility that is well displayed in battle.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/773.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (774, 'minior-red-meteor', 774, 60, 60, 100, 60, 100, 60, 3, 400, 'Originally making its home in the ozone layer, it hurtles to the ground when the shell enclosing its body grows too heavy.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/774.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (775, 'komala', 775, 65, 115, 65, 75, 95, 65, 4, 199, 'It is born asleep, and it dies asleep. All its movements are apparently no more than the results of it tossing and turning in its dreams.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/775.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (776, 'turtonator', 776, 60, 78, 135, 91, 85, 36, 20, 2120, 'The shell on its back is chemically unstable and explodes violently if struck. The hole in its stomach is its weak point.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/776.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (777, 'togedemaru', 777, 65, 98, 63, 40, 73, 96, 3, 33, 'The spiny fur on its back is normally at rest. When this Pokémon becomes agitated, its fur stands on end and stabs into its attackers.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/777.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (778, 'mimikyu-disguised', 778, 55, 90, 80, 50, 105, 96, 2, 7, 'Its actual appearance is unknown. A scholar who saw what was under its rag was overwhelmed by terror and died from the shock.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/778.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (779, 'bruxish', 779, 68, 105, 70, 70, 70, 92, 9, 190, 'When it unleashes its psychic power from the protuberance on its head, the grating sound of grinding teeth echoes through the area.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/779.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (780, 'drampa', 780, 78, 60, 85, 135, 91, 36, 30, 1850, 'It has a compassionate personality, but if it is angered, it completely destroys its surroundings with its intense breath.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/780.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (781, 'dhelmise', 781, 70, 131, 100, 86, 90, 40, 39, 2100, 'Swinging its massive anchor, it can KO Wailord in a single blow. What appears to be green seaweed is actually its body.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/781.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (782, 'jangmo-o', 782, 45, 55, 65, 45, 45, 45, 6, 297, 'It expresses its feelings by smacking its scales. Metallic sounds echo through the tall mountains where Jangmo-o lives.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/782.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (783, 'hakamo-o', 783, 55, 75, 90, 65, 70, 65, 12, 470, 'It leaps at its prey with a courageous shout. Its scaly punches tear its opponents to shreds.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/783.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (784, 'kommo-o', 784, 75, 110, 125, 100, 105, 85, 16, 782, 'When it spots enemies, it threatens them by jingling the scales on its tail. Weak opponents will crack and flee in panic.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/784.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (785, 'tapu-koko', 785, 70, 115, 85, 95, 75, 130, 18, 205, 'This guardian deity of Melemele is brimming with curiosity. It summons thunderclouds and stores their lightning inside its body.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/785.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (786, 'tapu-lele', 786, 70, 85, 75, 130, 115, 95, 12, 186, 'This guardian deity of Akala is guilelessly cruel. The fragrant aroma of flowers is the source of its energy.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/786.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (787, 'tapu-bulu', 787, 70, 130, 115, 85, 95, 75, 19, 455, 'It pulls large trees up by the roots and swings them around. It causes vegetation to grow, and then it absorbs energy from the growth.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/787.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (788, 'tapu-fini', 788, 70, 75, 115, 95, 130, 85, 13, 212, 'The dense fog it creates brings the downfall and destruction of its confused enemies. Ocean currents are the source of its energy.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/788.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (789, 'cosmog', 789, 43, 29, 31, 29, 31, 37, 2, 1, 'Its body is gaseous and frail. It slowly grows as it collects dust from the atmosphere.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/789.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (790, 'cosmoem', 790, 43, 29, 131, 29, 131, 37, 1, 9999, 'Motionless as if dead, its body is faintly warm to the touch. In the distant past, it was called the cocoon of the stars.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/790.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (791, 'solgaleo', 791, 137, 137, 107, 113, 89, 97, 34, 2300, 'It is said to live in another world. The intense light it radiates from the surface of its body can make the darkest of nights light up like midday.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/791.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (792, 'lunala', 792, 137, 113, 89, 137, 107, 97, 40, 1200, 'It is said to be a female evolution of Cosmog. When its third eye activates, away it flies to another world.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/792.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (793, 'nihilego', 793, 109, 53, 47, 127, 131, 103, 12, 555, 'One of several mysterious Ultra Beasts. People on the street report observing those infested by it suddenly becoming violent.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/793.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (794, 'buzzwole', 794, 107, 139, 139, 53, 53, 79, 24, 3336, 'This Ultra Beast appeared from another world. It shows off its body, but whether that display is a boast or a threat remains unclear.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/794.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (795, 'pheromosa', 795, 71, 137, 37, 137, 37, 151, 18, 250, 'One of the dangerous Ultra Beasts, it has been spotted running across the land at terrific speeds.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/795.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (796, 'xurkitree', 796, 83, 89, 71, 173, 71, 83, 38, 1000, 'One of the mysterious life-forms known as Ultra Beasts. Astonishing electric shocks emanate from its entire body, according to witnesses.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/796.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (797, 'celesteela', 797, 97, 101, 103, 107, 101, 61, 92, 9999, 'It appeared from the Ultra Wormhole. Witnesses observed it flying across the sky at high speed.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/797.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (798, 'kartana', 798, 59, 181, 131, 59, 31, 109, 3, 1, 'This Ultra Beast came from the Ultra Wormhole. It seems not to attack enemies on its own, but its sharp body is a dangerous weapon in itself.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/798.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (799, 'guzzlord', 799, 223, 101, 53, 97, 53, 43, 55, 8880, 'It has gobbled mountains and swallowed whole buildings, according to reports. It’s one of the Ultra Beasts.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/799.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (800, 'necrozma', 800, 97, 107, 101, 127, 89, 79, 24, 2300, 'Reminiscent of the Ultra Beasts, this life-form, apparently asleep underground, is thought to have come from another world in ancient times.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/800.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (801, 'magearna', 801, 80, 95, 115, 130, 115, 65, 10, 805, 'This artificial Pokémon, constructed more than 500 years ago, can understand human speech but cannot itself speak.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/801.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (802, 'marshadow', 802, 90, 125, 80, 90, 90, 125, 7, 222, 'Able to conceal itself in shadows, it never appears before humans, so its very existence was the stuff of myth.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/802.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (803, 'poipole', 803, 67, 73, 67, 73, 67, 73, 6, 18, 'This Ultra Beast is well enough liked to be chosen as a first partner in its own world.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/803.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (804, 'naganadel', 804, 73, 73, 73, 127, 73, 121, 36, 1500, 'It stores hundreds of liters of poisonous liquid inside its body. It is one of the organisms known as UBs.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/804.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (805, 'stakataka', 805, 61, 131, 211, 53, 101, 13, 55, 8200, 'It appeared from an Ultra Wormhole. Each one appears to be made up of many life-forms stacked one on top of each other.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/805.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (806, 'blacephalon', 806, 53, 127, 53, 151, 79, 107, 18, 130, 'It slithers toward people. Then, without warning, it triggers the explosion of its own head. It’s apparently one kind of Ultra Beast.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/806.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (807, 'zeraora', 807, 88, 112, 75, 102, 80, 143, 15, 445, 'It electrifies its claws and tears its opponents apart with them. Even if they dodge its attack, they’ll be electrocuted by the flying sparks.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/807.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (808, 'meltan', 808, 46, 65, 65, 55, 35, 34, 2, 80, 'It melts particles of iron and other metals found in the subsoil, so it can absorb them into its body of molten steel.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/808.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (809, 'melmetal', 809, 135, 143, 143, 80, 65, 34, 25, 8000, 'Revered long ago for its capacity to create iron from nothing, for some reason it has come back to life after 3,000 years.', 7, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/809.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (810, 'grookey', 810, 50, 65, 50, 40, 40, 65, 3, 50, 'When it uses its special stick to strike up a beat, the sound waves produced carry revitalizing energy to the plants and flowers in the area.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/810.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (811, 'thwackey', 811, 70, 85, 70, 55, 60, 80, 7, 140, 'The faster a Thwackey can beat out a rhythm with its two sticks, the more respect it wins from its peers.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/811.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (812, 'rillaboom', 812, 100, 125, 90, 60, 70, 85, 21, 900, 'By drumming, it taps into the power of its special tree stump. The roots of the stump follow its direction in battle.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/812.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (813, 'scorbunny', 813, 50, 71, 40, 40, 40, 69, 3, 45, 'A warm-up of running around gets fire energy coursing through this Pokémon’s body. Once that happens, it’s ready to fight at full power.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/813.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (814, 'raboot', 814, 65, 86, 60, 55, 60, 94, 6, 90, 'Its thick and fluffy fur protects it from the cold and enables it to use hotter fire moves.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/814.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (815, 'cinderace', 815, 80, 116, 75, 65, 75, 119, 14, 330, 'It juggles a pebble with its feet, turning it into a burning soccer ball. Its shots strike opponents hard and leave them scorched.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/815.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (816, 'sobble', 816, 50, 40, 40, 70, 40, 70, 3, 40, 'When scared, this Pokémon cries. Its tears pack the chemical punch of 100 onions, and attackers won’t be able to resist weeping.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/816.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (817, 'drizzile', 817, 65, 60, 55, 95, 55, 90, 7, 115, 'A clever combatant, this Pokémon battles using water balloons created with moisture secreted from its palms.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/817.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (818, 'inteleon', 818, 70, 85, 65, 125, 65, 120, 19, 452, 'It has many hidden capabilities, such as fingertips that can shoot water and a membrane on its back that it can use to glide through the air.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/818.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (819, 'skwovet', 819, 70, 55, 55, 35, 35, 25, 3, 25, 'Found throughout the Galar region, this Pokémon becomes uneasy if its cheeks are ever completely empty of berries.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/819.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (820, 'greedent', 820, 120, 95, 95, 55, 75, 20, 6, 60, 'It stashes berries in its tail—so many berries that they fall out constantly. But this Pokémon is a bit slow-witted, so it doesn’t notice the loss.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/820.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (821, 'rookidee', 821, 38, 47, 35, 33, 35, 57, 2, 18, 'It will bravely challenge any opponent, no matter how powerful. This Pokémon benefits from every battle—even a defeat increases its strength a bit.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/821.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (822, 'corvisquire', 822, 68, 67, 55, 43, 55, 77, 8, 160, 'Smart enough to use tools in battle, these Pokémon have been seen picking up rocks and flinging them or using ropes to wrap up enemies.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/822.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (823, 'corviknight', 823, 98, 87, 105, 53, 85, 67, 22, 750, 'This Pokémon reigns supreme in the skies of the Galar region. The black luster of its steel body could drive terror into the heart of any foe.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/823.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (824, 'blipbug', 824, 25, 20, 20, 25, 45, 45, 4, 80, 'A constant collector of information, this Pokémon is very smart. Very strong is what it isn’t.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/824.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (825, 'dottler', 825, 50, 35, 80, 50, 90, 30, 4, 195, 'It barely moves, but it’s still alive. Hiding in its shell without food or water seems to have awakened its psychic powers.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/825.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (826, 'orbeetle', 826, 60, 45, 110, 80, 120, 90, 4, 408, 'It’s famous for its high level of intelligence, and the large size of its brain is proof that it also possesses immense psychic power.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/826.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (827, 'nickit', 827, 40, 28, 28, 47, 52, 50, 6, 89, 'Aided by the soft pads on its feet, it silently raids the food stores of other Pokémon. It survives off its ill-gotten gains.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/827.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (828, 'thievul', 828, 70, 58, 58, 87, 92, 90, 12, 199, 'It secretly marks potential targets with a scent. By following the scent, it stalks its targets and steals from them when they least expect it.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/828.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (829, 'gossifleur', 829, 40, 40, 60, 40, 60, 10, 4, 22, 'It anchors itself in the ground with its single leg, then basks in the sun. After absorbing enough sunlight, its petals spread as it blooms brilliantly.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/829.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (830, 'eldegoss', 830, 60, 50, 90, 80, 120, 60, 5, 25, 'The seeds attached to its cotton fluff are full of nutrients. It spreads them on the wind so that plants and other Pokémon can benefit from them.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/830.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (831, 'wooloo', 831, 42, 40, 55, 40, 45, 48, 6, 60, 'Its curly fleece is such an effective cushion that this Pokémon could fall off a cliff and stand right back up at the bottom, unharmed.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/831.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (832, 'dubwool', 832, 72, 80, 100, 60, 90, 88, 13, 430, 'Weave a carpet from its springy wool, and you end up with something closer to a trampoline. You’ll start to bounce the moment you set foot on it.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/832.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (833, 'chewtle', 833, 50, 64, 50, 38, 38, 44, 3, 85, 'Apparently the itch of its teething impels it to snap its jaws at anything in front of it.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/833.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (834, 'drednaw', 834, 90, 115, 90, 48, 68, 74, 10, 1155, 'With jaws that can shear through steel rods, this highly aggressive Pokémon chomps down on its unfortunate prey.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/834.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (835, 'yamper', 835, 59, 45, 50, 40, 50, 26, 3, 135, 'This Pokémon is very popular as a herding dog in the Galar region. As it runs, it generates electricity from the base of its tail.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/835.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (836, 'boltund', 836, 69, 90, 60, 90, 60, 121, 10, 340, 'This Pokémon generates electricity and channels it into its legs to keep them going strong. Boltund can run nonstop for three full days.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/836.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (837, 'rolycoly', 837, 30, 40, 50, 40, 50, 30, 3, 120, 'Most of its body has the same composition as coal. Fittingly, this Pokémon was first discovered in coal mines about 400 years ago.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/837.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (838, 'carkol', 838, 80, 60, 90, 60, 70, 50, 11, 780, 'It forms coal inside its body. Coal dropped by this Pokémon once helped fuel the lives of people in the Galar region.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/838.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (839, 'coalossal', 839, 110, 80, 120, 80, 90, 30, 28, 3105, 'It’s usually peaceful, but the vandalism of mines enrages it. Offenders will be incinerated with flames that reach 2,700 degrees Fahrenheit.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/839.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (840, 'applin', 840, 40, 40, 80, 40, 40, 20, 2, 5, 'It spends its entire life inside an apple. It hides from its natural enemies, bird Pokémon, by pretending it’s just an apple and nothing more.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/840.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (841, 'flapple', 841, 70, 110, 80, 95, 60, 70, 3, 10, 'It ate a sour apple, and that induced its evolution. In its cheeks, it stores an acid capable of causing chemical burns.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/841.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (842, 'appletun', 842, 110, 85, 80, 100, 80, 30, 4, 130, 'Eating a sweet apple caused its evolution. A nectarous scent wafts from its body, luring in the bug Pokémon it preys on.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/842.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (843, 'silicobra', 843, 52, 57, 75, 35, 50, 46, 22, 76, 'As it digs, it swallows sand and stores it in its neck pouch. The pouch can hold more than 17 pounds of sand.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/843.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (844, 'sandaconda', 844, 72, 107, 125, 65, 70, 71, 38, 655, 'When it contracts its body, over 220 pounds of sand sprays from its nose. If it ever runs out of sand, it becomes disheartened.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/844.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (845, 'cramorant', 845, 70, 85, 55, 85, 95, 85, 8, 180, 'It’s so strong that it can knock out some opponents in a single hit, but it also may forget what it’s battling midfight.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/845.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (846, 'arrokuda', 846, 41, 63, 40, 40, 30, 66, 5, 10, 'If it sees any movement around it, this Pokémon charges for it straightaway, leading with its sharply pointed jaw. It’s very proud of that jaw.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/846.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (847, 'barraskewda', 847, 61, 123, 60, 60, 50, 136, 13, 300, 'This Pokémon has a jaw that’s as sharp as a spear and as strong as steel. Apparently Barraskewda’s flesh is surprisingly tasty, too.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/847.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (848, 'toxel', 848, 40, 38, 35, 54, 35, 40, 4, 110, 'It stores poison in an internal poison sac and secretes that poison through its skin. If you touch this Pokémon, a tingling sensation follows.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/848.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (849, 'toxtricity-amped', 849, 75, 98, 70, 114, 70, 75, 16, 400, 'When this Pokémon sounds as if it’s strumming a guitar, it’s actually clawing at the protrusions on its chest to generate electricity.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/849.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (850, 'sizzlipede', 850, 50, 65, 45, 50, 50, 45, 7, 10, 'It stores flammable gas in its body and uses it to generate heat. The yellow sections on its belly get particularly hot.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/850.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (851, 'centiskorch', 851, 100, 115, 65, 90, 90, 65, 30, 1200, 'When it heats up, its body temperature reaches about 1,500 degrees Fahrenheit. It lashes its body like a whip and launches itself at enemies.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/851.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (852, 'clobbopus', 852, 50, 68, 60, 50, 50, 32, 6, 40, 'It’s very curious, but its means of investigating things is to try to punch them with its tentacles. The search for food is what brings it onto land.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/852.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (853, 'grapploct', 853, 80, 118, 90, 70, 80, 42, 16, 390, 'A body made up of nothing but muscle makes the grappling moves this Pokémon performs with its tentacles tremendously powerful.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/853.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (854, 'sinistea', 854, 40, 45, 45, 74, 54, 50, 1, 2, 'This Pokémon is said to have been born when a lonely spirit possessed a cold, leftover cup of tea.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/854.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (855, 'polteageist', 855, 60, 65, 65, 134, 114, 70, 2, 4, 'This species lives in antique teapots. Most pots are forgeries, but on rare occasions, an authentic work is found.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/855.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (856, 'hatenna', 856, 42, 30, 45, 56, 53, 39, 4, 34, 'Via the protrusion on its head, it senses other creatures’ emotions. If you don’t have a calm disposition, it will never warm up to you.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/856.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (857, 'hattrem', 857, 57, 40, 65, 86, 73, 49, 6, 48, 'No matter who you are, if you bring strong emotions near this Pokémon, it will silence you violently.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/857.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (858, 'hatterene', 858, 57, 90, 95, 136, 103, 29, 21, 51, 'It emits psychic power strong enough to cause headaches as a deterrent to the approach of others.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/858.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (859, 'impidimp', 859, 45, 45, 30, 55, 40, 50, 4, 55, 'Through its nose, it sucks in the emanations produced by people and Pokémon when they feel annoyed. It thrives off this negative energy.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/859.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (860, 'morgrem', 860, 65, 60, 45, 75, 55, 70, 8, 125, 'When it gets down on all fours as if to beg for forgiveness, it’s trying to lure opponents in so that it can stab them with its spear-like hair.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/860.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (861, 'grimmsnarl', 861, 95, 120, 65, 95, 75, 60, 15, 610, 'With the hair wrapped around its body helping to enhance its muscles, this Pokémon can overwhelm even Machamp.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/861.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (862, 'obstagoon', 862, 93, 90, 101, 60, 81, 95, 16, 460, 'Its voice is staggering in volume. Obstagoon has a tendency to take on a threatening posture and shout—this move is known as Obstruct.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/862.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (863, 'perrserker', 863, 70, 110, 100, 50, 60, 50, 8, 280, 'What appears to be an iron helmet is actually hardened hair. This Pokémon lives for the thrill of battle.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/863.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (864, 'cursola', 864, 60, 95, 50, 145, 130, 30, 10, 4, 'Its shell is overflowing with its heightened otherworldly energy. The ectoplasm serves as protection for this Pokémon’s core spirit.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/864.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (865, 'sirfetchd', 865, 62, 135, 95, 68, 82, 65, 8, 1170, 'Only Farfetch’d that have survived many battles can attain this evolution. When this Pokémon’s leek withers, it will retire from combat.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/865.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (866, 'mr-rime', 866, 80, 85, 75, 110, 100, 70, 15, 582, 'It’s highly skilled at tap-dancing. It waves its cane of ice in time with its graceful movements.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/866.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (867, 'runerigus', 867, 58, 95, 145, 50, 105, 30, 16, 666, 'A powerful curse was woven into an ancient painting. After absorbing the spirit of a Yamask, the painting began to move.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/867.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (868, 'milcery', 868, 45, 40, 40, 50, 61, 34, 2, 3, 'This Pokémon was born from sweet-smelling particles in the air. Its body is made of cream.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/868.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (869, 'alcremie', 869, 65, 60, 75, 110, 121, 64, 3, 5, 'When it trusts a Trainer, it will treat them to berries it’s decorated with cream.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/869.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (870, 'falinks', 870, 65, 100, 100, 70, 60, 75, 30, 620, 'Five of them are troopers, and one is the brass. The brass’s orders are absolute.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/870.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (871, 'pincurchin', 871, 48, 101, 95, 91, 85, 15, 3, 10, 'It feeds on seaweed, using its teeth to scrape it off rocks. Electric current flows from the tips of its spines.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/871.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (872, 'snom', 872, 30, 25, 35, 45, 30, 20, 3, 38, 'It spits out thread imbued with a frigid sort of energy and uses it to tie its body to branches, disguising itself as an icicle while it sleeps.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/872.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (873, 'frosmoth', 873, 70, 65, 60, 125, 90, 65, 13, 420, 'Icy scales fall from its wings like snow as it flies over fields and mountains. The temperature of its wings is less than −290 degrees Fahrenheit.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/873.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (874, 'stonjourner', 874, 100, 125, 135, 20, 20, 70, 25, 5200, 'It stands in grasslands, watching the sun’s descent from zenith to horizon. This Pokémon has a talent for delivering dynamic kicks.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/874.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (875, 'eiscue-ice', 875, 75, 80, 110, 65, 90, 50, 14, 890, 'It drifted in on the flow of ocean waters from a frigid place. It keeps its head iced constantly to make sure it stays nice and cold.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/875.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (876, 'indeedee-male', 876, 60, 65, 55, 105, 95, 95, 9, 280, 'It uses the horns on its head to sense the emotions of others. Males will act as valets for those they serve, looking after their every need.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/876.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (877, 'morpeko-full-belly', 877, 58, 95, 58, 70, 58, 97, 3, 30, 'As it eats the seeds stored up in its pocket-like pouches, this Pokémon is not just satisfying its constant hunger. It’s also generating electricity.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/877.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (878, 'cufant', 878, 72, 80, 49, 40, 49, 40, 12, 1000, 'It digs up the ground with its trunk. It’s also very strong, being able to carry loads of over five tons without any problem at all.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/878.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (879, 'copperajah', 879, 122, 130, 69, 80, 69, 30, 30, 6500, 'They came over from another region long ago and worked together with humans. Their green skin is resistant to water.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/879.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (880, 'dracozolt', 880, 90, 100, 90, 80, 70, 75, 18, 1900, 'In ancient times, it was unbeatable thanks to its powerful lower body, but it went extinct anyway after it depleted all its plant-based food sources.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/880.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (881, 'arctozolt', 881, 90, 100, 90, 90, 80, 55, 23, 1500, 'The shaking of its freezing upper half is what generates its electricity. It has a hard time walking around.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/881.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (882, 'dracovish', 882, 90, 90, 100, 70, 80, 75, 23, 2150, 'Powerful legs and jaws made it the apex predator of its time. Its own overhunting of its prey was what drove it to extinction.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/882.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (883, 'arctovish', 883, 90, 90, 100, 80, 90, 55, 20, 1750, 'Though it’s able to capture prey by freezing its surroundings, it has trouble eating the prey afterward because its mouth is on top of its head.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/883.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (884, 'duraludon', 884, 70, 95, 115, 120, 50, 85, 18, 400, 'Its body resembles polished metal, and it’s both lightweight and strong. The only drawback is that it rusts easily.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/884.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (885, 'dreepy', 885, 28, 60, 30, 40, 30, 82, 5, 20, 'After being reborn as a ghost Pokémon, Dreepy wanders the areas it used to inhabit back when it was alive in prehistoric seas.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/885.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (886, 'drakloak', 886, 68, 80, 50, 60, 50, 102, 14, 110, 'It’s capable of flying faster than 120 mph. It battles alongside Dreepy and dotes on them until they successfully evolve.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/886.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (887, 'dragapult', 887, 88, 120, 75, 100, 75, 142, 30, 500, 'When it isn’t battling, it keeps Dreepy in the holes on its horns. Once a fight starts, it launches the Dreepy like supersonic missiles.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/887.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (888, 'zacian', 888, 92, 120, 115, 80, 115, 138, 28, 1100, 'Known as a legendary hero, this Pokémon absorbs metal particles, transforming them into a weapon it uses to battle.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/888.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (889, 'zamazenta', 889, 92, 120, 115, 80, 115, 138, 29, 2100, 'In times past, it worked together with a king of the people to save the Galar region. It absorbs metal that it then uses in battle.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/889.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (890, 'eternatus', 890, 140, 85, 95, 145, 95, 130, 200, 9500, 'The core on its chest absorbs energy emanating from the lands of the Galar region. This energy is what allows Eternatus to stay active.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/890.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (891, 'kubfu', 891, 60, 90, 60, 53, 50, 72, 6, 120, 'Kubfu trains hard to perfect its moves. The moves it masters will determine which form it takes when it evolves.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/891.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (892, 'urshifu-single-strike', 892, 100, 130, 100, 63, 60, 97, 19, 1050, 'This form of Urshifu is a strong believer in the one-hit KO. Its strategy is to leap in close to foes and land a devastating blow with a hardened fist.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/892.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (893, 'zarude', 893, 105, 120, 105, 70, 95, 105, 18, 700, 'Within dense forests, this Pokémon lives in a pack with others of its kind. It’s incredibly aggressive, and the other Pokémon of the forest fear it.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/893.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (894, 'regieleki', 894, 80, 100, 50, 100, 50, 200, 12, 1450, 'This Pokémon is a cluster of electrical energy. It’s said that removing the rings on Regieleki’s body will unleash the Pokémon’s latent power.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/894.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (895, 'regidrago', 895, 200, 100, 50, 100, 50, 80, 21, 2000, 'An academic theory proposes that Regidrago’s arms were once the head of an ancient dragon Pokémon. The theory remains unproven.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/895.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (896, 'glastrier', 896, 100, 145, 130, 65, 110, 30, 22, 8000, 'Glastrier emits intense cold from its hooves. It’s also a belligerent Pokémon—anything it wants, it takes by force.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/896.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (897, 'spectrier', 897, 100, 65, 60, 145, 80, 130, 20, 445, 'It probes its surroundings with all its senses save one—it doesn’t use its sense of sight. Spectrier’s kicks are said to separate soul from body.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/897.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (898, 'calyrex', 898, 100, 80, 80, 80, 80, 80, 11, 77, 'Calyrex is a merciful Pokémon, capable of providing healing and blessings. It reigned over the Galar region in times of yore.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/898.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (899, 'wyrdeer', 899, 103, 105, 72, 105, 75, 65, 18, 951, 'The black orbs shine with an uncanny light when the Pokémon is erecting invisible barriers. The fur shed from its beard retains heat well and is a highly useful material for winter clothing.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/899.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (900, 'kleavor', 900, 70, 135, 95, 45, 70, 85, 18, 890, 'A violent creature that fells towering trees with its crude axes and shields itself with hard stone. If one should chance upon this Pokémon in the wilds, one''s only recourse is to flee.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/900.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (901, 'ursaluna', 901, 130, 140, 105, 45, 80, 50, 24, 2900, 'I believe it was Hisui''s swampy terrain that gave Ursaluna its burly physique and newfound capacity to manipulate peat at will.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/901.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (902, 'basculegion-male', 902, 120, 112, 65, 80, 75, 78, 30, 1100, 'Clads itself in the souls of comrades that perished before fulfilling their goals of journeying upstream. No other species throughout all Hisui''s rivers is Basculegion''s equal.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/902.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (903, 'sneasler', 903, 80, 130, 60, 40, 80, 120, 13, 430, 'Because of Sneasler''s virulent poison and daunting physical prowess, no other species could hope to best it on the frozen highlands. Preferring solitude, this species does not form packs.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/903.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (904, 'overqwil', 904, 85, 115, 95, 65, 65, 85, 25, 605, 'Its lancelike spikes and savage temperament have earned it the nickname ”sea fiend.” It slurps up poison to nourish itself.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/904.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (905, 'enamorus-incarnate', 905, 74, 115, 70, 135, 80, 106, 16, 480, 'When it flies to this land from across the sea, the bitter winter comes to an end. According to legend, this Pokémon''s love gives rise to the budding of fresh life across Hisui.', 8, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/905.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (906, 'sprigatito', 906, 40, 61, 54, 45, 45, 65, 4, 41, 'Its fluffy fur is similar in composition to plants. This Pokémon frequently washes its face to keep it from drying out.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/906.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (907, 'floragato', 907, 61, 80, 63, 60, 63, 83, 9, 122, 'Floragato deftly wields the vine hidden beneath its long fur, slamming the hard flower bud against its opponents.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/907.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (908, 'meowscarada', 908, 76, 110, 70, 81, 70, 123, 15, 312, 'This Pokémon uses the reflective fur lining its cape to camouflage the stem of its flower, creating the illusion that the flower is floating.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/908.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (909, 'fuecoco', 909, 67, 45, 59, 63, 40, 36, 4, 98, 'It lies on warm rocks and uses the heat absorbed by its square-shaped scales to create fire energy.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/909.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (910, 'crocalor', 910, 81, 55, 78, 90, 58, 49, 10, 307, 'The combination of Crocalor’s fire energy and overflowing vitality has caused an egg-shaped fireball to appear on the Pokémon’s head.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/910.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (911, 'skeledirge', 911, 104, 75, 100, 110, 75, 66, 16, 3265, 'The fiery bird changes shape when Skeledirge sings. Rumor has it that the bird was born when the fireball on Skeledirge’s head gained a soul.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/911.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (912, 'quaxly', 912, 55, 65, 45, 50, 45, 50, 5, 61, 'This Pokémon migrated to Paldea from distant lands long ago. The gel secreted by its feathers repels water and grime."', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/912.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (913, 'quaxwell', 913, 70, 85, 65, 65, 60, 65, 12, 215, 'These Pokémon constantly run through shallow waters to train their legs, then compete with each other to see which of them kicks most gracefully.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/913.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (914, 'quaquaval', 914, 85, 120, 80, 85, 75, 85, 18, 619, 'A single kick from a Quaquaval can send a truck rolling. This Pokémon uses its powerful legs to perform striking dances from far-off lands.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/914.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (915, 'lechonk', 915, 54, 45, 40, 35, 45, 35, 5, 102, 'It searches for food all day. It possesses a keen sense of smell but doesn’t use it for anything other than foraging.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/915.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (916, 'oinkologne-male', 916, 110, 100, 75, 59, 80, 65, 10, 1200, 'Oinkologne is proud of its fine, glossy skin. It emits a concentrated scent from the tip of its tail.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/916.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (917, 'tarountula', 917, 35, 41, 45, 29, 40, 20, 3, 40, 'The ball of threads wrapped around its body is elastic enough to deflect the scythes of Scyther, this Pokémon’s natural enemy.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/917.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (918, 'spidops', 918, 60, 79, 92, 52, 86, 35, 10, 165, 'It clings to branches and ceilings using its threads and moves without a sound. It takes out its prey before the prey even notices it.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/918.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (919, 'nymble', 919, 33, 46, 40, 21, 25, 45, 2, 10, 'It has its third set of legs folded up. When it’s in a tough spot, this Pokémon jumps over 30 feet using the strength of its legs.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/919.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (920, 'lokix', 920, 71, 102, 78, 52, 55, 92, 10, 175, 'When it decides to fight all out, it stands on its previously folded legs to enter Showdown Mode. It neutralizes its enemies in short order.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/920.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (921, 'pawmi', 921, 45, 50, 20, 40, 25, 60, 3, 25, 'It has underdeveloped electric sacs on its cheeks. These sacs can produce electricity only if Pawmi rubs them furiously with the pads on its forepaws.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/921.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (922, 'pawmo', 922, 60, 75, 40, 50, 40, 85, 4, 65, 'When its group is attacked, Pawmo is the first to leap into battle, defeating enemies with a fighting technique that utilizes electric shocks.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/922.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (923, 'pawmot', 923, 70, 115, 70, 70, 60, 105, 9, 410, 'This Pokémon normally is slow to react, but once it enters battle, it will strike down its enemies with lightning-fast movements.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/923.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (924, 'tandemaus', 924, 50, 50, 45, 40, 45, 75, 3, 18, 'Exhibiting great teamwork, they use their incisors to cut pieces out of any material that might be useful for a nest, then make off with them.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/924.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (925, 'maushold-family-of-four', 925, 74, 75, 70, 65, 75, 111, 3, 23, 'The two little ones just appeared one day. The group might be a family of related Pokémon, but nobody knows for sure.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/925.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (926, 'fidough', 926, 37, 55, 70, 30, 55, 65, 3, 109, 'This Pokémon is smooth and moist to the touch. Yeast in Fidough’s breath induces fermentation in the Pokémon’s vicinity.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/926.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (927, 'dachsbun', 927, 57, 80, 115, 50, 80, 95, 5, 149, 'The pleasant aroma that emanates from this Pokémon’s body helps wheat grow, so Dachsbun has been treasured by farming villages.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/927.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (928, 'smoliv', 928, 41, 35, 45, 58, 51, 30, 3, 65, 'It protects itself from enemies by emitting oil from the fruit on its head. This oil is bitter and astringent enough to make someone flinch.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/928.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (929, 'dolliv', 929, 52, 53, 60, 78, 78, 33, 6, 119, 'Dolliv shares its tasty, fresh-scented oil with others. This species has coexisted with humans since times long gone.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/929.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (930, 'arboliva', 930, 78, 69, 90, 125, 109, 39, 14, 482, 'This calm Pokémon is very compassionate. It will share its delicious, nutrient-rich oil with weakened Pokémon.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/930.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (931, 'squawkabilly-green-plumage', 931, 82, 96, 51, 45, 51, 92, 6, 24, 'These Pokémon prefer to live in cities. They form flocks based on the color of their feathers, and they fight over territory.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/931.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (932, 'nacli', 932, 55, 55, 75, 35, 35, 25, 4, 160, 'It was born in a layer of rock salt deep under the earth. This species was particularly treasured in the old days, as they would share precious salt.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/932.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (933, 'naclstack', 933, 60, 60, 100, 35, 65, 35, 6, 1050, 'This Pokémon dry cures its prey by spraying salt over them. The curing process steals away the water in the prey’s body.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/933.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (934, 'garganacl', 934, 100, 100, 130, 45, 90, 35, 23, 2400, 'Garganacl will rub its fingertips together and sprinkle injured Pokémon with salt. Even severe wounds will promptly heal afterward.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/934.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (935, 'charcadet', 935, 40, 50, 40, 50, 40, 35, 6, 105, 'Burnt charcoal came to life and became a Pokémon. Possessing a fiery fighting spirit, Charcadet will battle even tough opponents.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/935.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (936, 'armarouge', 936, 85, 60, 100, 125, 80, 75, 15, 850, 'Armarouge evolved through the use of a set of armor that belonged to a distinguished warrior. This Pokémon is incredibly loyal.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/936.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (937, 'ceruledge', 937, 75, 125, 80, 60, 100, 85, 16, 620, 'The fiery blades on its arms burn fiercely with the lingering resentment of a sword wielder who fell before accomplishing their goal.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/937.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (938, 'tadbulb', 938, 61, 31, 41, 59, 35, 45, 3, 4, 'Tadbulb shakes its tail to generate electricity. If it senses danger, it will make its head blink on and off to alert its allies.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/938.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (939, 'bellibolt', 939, 109, 64, 91, 103, 83, 45, 12, 1130, 'When this Pokémon expands and contracts its wobbly body, the belly-button dynamo in its stomach produces a huge amount of electricity.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/939.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (940, 'wattrel', 940, 40, 40, 35, 55, 40, 70, 4, 36, 'When its wings catch the wind, the bones within produce electricity. This Pokémon dives into the ocean, catching prey by electrocuting them.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/940.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (941, 'kilowattrel', 941, 70, 70, 60, 105, 60, 125, 14, 386, 'Kilowattrel inflates its throat sac to amplify its electricity. By riding the wind, this Pokémon can fly over 430 miles in a day.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/941.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (942, 'maschiff', 942, 60, 78, 60, 40, 51, 51, 5, 160, 'It always scowls in an attempt to make opponents take it seriously, but even crying children will burst into laughter when they see Maschiff’s face.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/942.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (943, 'mabosstiff', 943, 80, 120, 90, 60, 70, 85, 11, 610, 'This Pokémon can store energy in its large dewlap. Mabosstiff unleashes this energy all at once to blow away enemies.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/943.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (944, 'shroodle', 944, 40, 65, 35, 40, 35, 75, 2, 7, 'Though usually a mellow Pokémon, it will sink its sharp, poison-soaked front teeth into any that anger it, causing paralysis in the object of its ire.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/944.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (945, 'grafaiai', 945, 63, 95, 65, 80, 72, 110, 7, 272, 'The color of the poisonous saliva depends on what the Pokémon eats. Grafaiai covers its fingers in its saliva and draws patterns on trees in forests.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/945.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (946, 'bramblin', 946, 40, 65, 30, 45, 35, 60, 6, 6, 'A soul unable to move on to the afterlife was blown around by the wind until it got tangled up with dried grass and became a Pokémon.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/946.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (947, 'brambleghast', 947, 55, 115, 70, 80, 70, 90, 12, 60, 'It will open the branches of its head to envelop its prey. Once it absorbs all the life energy it needs, it expels the prey and discards it.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/947.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (948, 'toedscool', 948, 40, 40, 35, 50, 100, 70, 9, 330, 'Toedscool lives in muggy forests. The flaps that fall from its body are chewy and very delicious.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/948.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (949, 'toedscruel', 949, 80, 70, 65, 80, 120, 100, 19, 580, 'These Pokémon gather into groups and form colonies deep within forests. They absolutely hate it when strangers approach.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/949.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (950, 'klawf', 950, 70, 100, 115, 35, 55, 75, 13, 790, 'Klawf hangs upside-down from cliffs, waiting for prey. But Klawf can’t remain in this position for long because its blood rushes to its head.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/950.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (951, 'capsakid', 951, 50, 62, 40, 62, 40, 50, 3, 30, 'The more sunlight this Pokémon bathes in, the more spicy chemicals are produced by its body, and thus the spicier its moves become.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/951.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (952, 'scovillain', 952, 65, 108, 65, 108, 65, 75, 9, 150, 'The red head converts spicy chemicals into fire energy and blasts the surrounding area with a super spicy stream of flame.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/952.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (953, 'rellor', 953, 41, 50, 60, 31, 58, 30, 2, 10, 'This Pokémon creates a mud ball by mixing sand and dirt with psychic energy. It treasures its mud ball more than its own life.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/953.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (954, 'rabsca', 954, 75, 50, 85, 115, 100, 45, 3, 35, 'The body that supports the ball barely moves. Therefore, it is thought that the true body of this Pokémon is actually inside the ball.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/954.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (955, 'flittle', 955, 30, 35, 30, 55, 30, 75, 2, 15, 'Flittle’s toes levitate about half an inch above the ground because of the psychic power emitted from the frills on the Pokémon’s belly.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/955.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (956, 'espathra', 956, 95, 60, 60, 101, 60, 105, 19, 900, 'It immobilizes opponents by bathing them in psychic power from its large eyes. Despite its appearance, it has a vicious temperament.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/956.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (957, 'tinkatink', 957, 50, 45, 45, 35, 64, 58, 4, 89, 'It swings its handmade hammer around to protect itself, but the hammer is often stolen by Pokémon that eat metal.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/957.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (958, 'tinkatuff', 958, 65, 55, 55, 45, 82, 78, 7, 591, 'This Pokémon will attack groups of Pawniard and Bisharp, gathering metal from them in order to create a large and sturdy hammer.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/958.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (959, 'tinkaton', 959, 85, 75, 77, 70, 105, 94, 7, 1128, 'This intelligent Pokémon has a very daring disposition. It knocks rocks into the sky with its hammer, aiming for flying Corviknight.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/959.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (960, 'wiglett', 960, 10, 55, 25, 35, 25, 95, 12, 18, 'This Pokémon can pick up the scent of a Veluza just over 65 feet away and will hide itself in the sand.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/960.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (961, 'wugtrio', 961, 35, 100, 50, 50, 70, 120, 12, 54, 'It has a vicious temperament, contrary to what its appearance may suggest. It wraps its long bodies around prey, then drags the prey into its den.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/961.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (962, 'bombirdier', 962, 70, 103, 85, 60, 85, 82, 15, 429, 'It gathers things up in an apron made from shed feathers added to the Pokémon’s chest feathers, then drops those things from high places for fun.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/962.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (963, 'finizen', 963, 70, 45, 40, 45, 40, 75, 13, 602, 'It likes playing with others of its kind using the water ring on its tail. It uses ultrasonic waves to sense the emotions of other living creatures.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/963.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (964, 'palafin-zero', 964, 100, 70, 72, 53, 62, 100, 13, 602, 'This Pokémon changes its appearance if it hears its allies calling for help. Palafin will never show anybody its moment of transformation.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/964.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (965, 'varoom', 965, 45, 70, 63, 30, 45, 47, 10, 350, 'It is said that this Pokémon was born when an unknown poison Pokémon entered and inspirited an engine left at a scrap-processing factory.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/965.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (966, 'revavroom', 966, 80, 119, 90, 54, 67, 90, 18, 1200, 'It creates a gas out of poison and minerals from rocks. It then detonates the gas in its cylinders—now numbering eight—to generate energy.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/966.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (967, 'cyclizar', 967, 70, 95, 65, 85, 65, 121, 16, 630, 'Apparently Cyclizar has been allowing people to ride on its back since ancient times. Depictions of this have been found in 10,000-year-old murals.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/967.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (968, 'orthworm', 968, 70, 85, 145, 60, 55, 65, 25, 3100, 'When attacked, this Pokémon will wield the tendrils on its body like fists and pelt the opponent with a storm of punches.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/968.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (969, 'glimmet', 969, 48, 35, 42, 105, 60, 60, 7, 80, 'It absorbs nutrients from cave walls. The petals it wears are made of crystallized poison.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/969.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (970, 'glimmora', 970, 83, 55, 90, 130, 81, 86, 15, 450, 'When this Pokémon detects danger, it will open up its crystalline petals and fire beams from its conical body.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/970.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (971, 'greavard', 971, 50, 61, 60, 30, 55, 34, 6, 350, 'It is said that a dog Pokémon that died in the wild without ever interacting with a human was reborn as this Pokémon.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/971.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (972, 'houndstone', 972, 72, 101, 100, 50, 97, 68, 20, 150, 'Houndstone spends most of its time sleeping in graveyards. Among all the dog Pokémon, this one is most loyal to its master.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/972.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (973, 'flamigo', 973, 82, 115, 74, 75, 64, 90, 16, 370, 'This Pokémon apparently ties the base of its neck into a knot so that energy stored in its belly does not escape from its beak.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/973.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (974, 'cetoddle', 974, 108, 68, 45, 30, 40, 43, 12, 450, 'This species left the ocean and began living on land a very long time ago. It seems to be closely related to Wailmer.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/974.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (975, 'cetitan', 975, 170, 113, 65, 45, 55, 73, 45, 7000, 'This Pokémon wanders around snowy, icy areas. It protects its body with powerful muscles and a thick layer of fat under its skin.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/975.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (976, 'veluza', 976, 90, 102, 73, 78, 65, 70, 25, 900, 'When Veluza discards unnecessary flesh, its mind becomes honed and its psychic power increases. The spare flesh has a mild but delicious flavor.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/976.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (977, 'dondozo', 977, 150, 100, 115, 65, 65, 35, 120, 2200, 'This Pokémon is a glutton, but it’s bad at getting food. It teams up with a Tatsugiri to catch prey.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/977.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (978, 'tatsugiri-curly', 978, 68, 50, 60, 120, 95, 82, 3, 80, 'This is a small dragon Pokémon. It lives inside the mouth of Dondozo to protect itself from enemies on the outside.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/978.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (979, 'annihilape', 979, 110, 115, 80, 50, 90, 90, 12, 560, 'When its anger rose beyond a critical point, this Pokémon gained power that is unfettered by the limits of its physical body.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/979.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (980, 'clodsire', 980, 130, 75, 60, 45, 100, 20, 18, 2230, 'When attacked, this Pokémon will retaliate by sticking thick spines out from its body. It’s a risky move that puts everything on the line.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/980.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (981, 'farigiraf', 981, 120, 90, 70, 110, 70, 60, 32, 1600, 'Now that the brain waves from the head and tail are synced up, the psychic power of this Pokémon is 10 times stronger than Girafarig’s.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/981.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (982, 'dudunsparce-two-segment', 982, 125, 100, 80, 85, 75, 55, 36, 392, 'This Pokémon uses its hard tail to make its nest by boring holes into bedrock deep underground. The nest can reach lengths of over six miles.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/982.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (983, 'kingambit', 983, 100, 135, 120, 60, 85, 50, 20, 1200, 'Only a Bisharp that stands above all others in its vast army can evolve into Kingambit.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/983.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (984, 'great-tusk', 984, 115, 131, 131, 53, 53, 87, 22, 3200, 'Sightings of this Pokémon have occurred in recent years. The name Great Tusk was taken from a creature listed in a certain book.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/984.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (985, 'scream-tail', 985, 115, 65, 99, 65, 115, 111, 12, 80, 'There has been only one reported sighting of this Pokémon. It resembles a mysterious creature depicted in an old expedition journal.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/985.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (986, 'brute-bonnet', 986, 111, 127, 99, 79, 99, 55, 12, 210, 'It is possible that the creature listed as Brute Bonnet in a certain book could actually be this Pokémon.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/986.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (987, 'flutter-mane', 987, 55, 55, 55, 135, 135, 135, 14, 40, 'This Pokémon has characteristics similar to those of Flutter Mane, a creature mentioned in a certain book.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/987.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (988, 'slither-wing', 988, 85, 135, 79, 85, 105, 81, 32, 920, 'This mysterious Pokémon has some similarities to a creature that an old book introduced as Slither Wing.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/988.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (989, 'sandy-shocks', 989, 85, 81, 97, 121, 85, 101, 23, 600, 'No records exist of this Pokémon being caught. Data is lacking, but the Pokémon’s traits match up with a creature shown in an expedition journal.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/989.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (990, 'iron-treads', 990, 90, 112, 120, 72, 70, 106, 9, 2400, 'This Pokémon closely resembles a scientific weapon that a paranormal magazine claimed was sent to this planet by aliens.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/990.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (991, 'iron-bundle', 991, 56, 80, 114, 124, 60, 136, 6, 110, 'Its shape is similar to a robot featured in a paranormal magazine article. The robot was said to have been created by an ancient civilization.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/991.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (992, 'iron-hands', 992, 154, 140, 108, 50, 68, 50, 18, 3807, 'It is very similar to a cyborg covered exclusively by a paranormal magazine. The cyborg was said to be the modified form of a certain athlete.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/992.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (993, 'iron-jugulis', 993, 94, 80, 86, 122, 80, 108, 13, 1110, 'It resembles a certain Pokémon introduced in a paranormal magazine, described as the offspring of a Hydreigon that fell in love with a robot.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/993.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (994, 'iron-moth', 994, 80, 70, 60, 140, 110, 110, 12, 360, 'This Pokémon resembles an unknown object described in a paranormal magazine as a UFO sent to observe humanity.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/994.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (995, 'iron-thorns', 995, 100, 134, 110, 70, 84, 72, 16, 3030, 'It has some similarities to a Pokémon introduced in a dubious magazine as a Tyranitar from one billion years into the future.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/995.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (996, 'frigibax', 996, 65, 75, 45, 35, 45, 55, 5, 170, 'Frigibax absorbs heat through its dorsal fin and converts the heat into ice energy. The higher the temperature, the more energy Frigibax stores.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/996.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (997, 'arctibax', 997, 90, 95, 66, 45, 65, 62, 8, 300, 'Arctibax freezes the air around it, protecting its face with an ice mask and turning its dorsal fin into a blade of ice.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/997.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (998, 'baxcalibur', 998, 115, 145, 92, 75, 86, 87, 21, 2100, 'This Pokémon blasts cryogenic air out from its mouth. This air can instantly freeze even liquid-hot lava.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/998.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (999, 'gimmighoul', 999, 45, 30, 70, 75, 70, 10, 3, 50, 'This Pokémon was born inside a treasure chest about 1,500 years ago. It sucks the life-force out of scoundrels who try to steal the treasure.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/999.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1000, 'gholdengo', 1000, 87, 60, 95, 133, 91, 84, 12, 300, 'Its body seems to be made up of 1,000 coins. This Pokémon gets along well with others and is quick to make friends with anybody.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1000.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1001, 'wo-chien', 1001, 85, 85, 100, 95, 135, 70, 15, 742, 'The grudge of a person punished for writing the king’s evil deeds upon wooden tablets has clad itself in dead leaves to become a Pokémon.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1001.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1002, 'chien-pao', 1002, 80, 120, 80, 90, 65, 135, 19, 1522, 'This Pokémon can control 100 tons of fallen snow. It plays around innocently by leaping in and out of avalanches it has caused.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1002.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1003, 'ting-lu', 1003, 155, 110, 125, 55, 80, 45, 27, 6997, 'The fear poured into an ancient ritual vessel has clad itself in rocks and dirt to become a Pokémon.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1003.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1004, 'chi-yu', 1004, 55, 80, 80, 135, 120, 100, 4, 49, 'It controls flames burning at over 5,400 degrees Fahrenheit. It casually swims through the sea of lava it creates by melting rock and sand.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1004.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1005, 'roaring-moon', 1005, 105, 139, 71, 55, 101, 119, 20, 3800, 'It is possible that this is the creature listed as Roaring Moon in an expedition journal that still holds many mysteries.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1005.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1006, 'iron-valiant', 1006, 74, 130, 90, 120, 60, 116, 14, 350, 'It has some similarities to a mad scientist’s invention covered in a paranormal magazine.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1006.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1007, 'koraidon', 1007, 100, 135, 115, 85, 100, 135, 25, 3030, 'This seems to be the Winged King mentioned in an old expedition journal. It was said to have split the land with its bare fists.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1007.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1008, 'miraidon', 1008, 100, 85, 100, 135, 115, 135, 35, 2400, 'Much remains unknown about this creature. It resembles Cyclizar, but it is far more ruthless and powerful.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1008.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1009, 'walking-wake', 1009, 99, 83, 91, 125, 83, 109, 35, 2800, 'This ferocious creature is shrouded in mystery. It''s named after an aquatic monster mentioned in an old expedition journal.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1009.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1010, 'iron-leaves', 1010, 90, 130, 88, 70, 108, 104, 15, 1250, 'Many of its physical characteristics match those of a Virizion from the future that was covered in a paranormal magazine.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1010.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1011, 'dipplin', 1011, 80, 80, 110, 95, 80, 40, 4, 97, 'Dipplin is two creatures in one Pokémon. Its evolution was triggered by a special apple grown only in one place.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1011.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1012, 'poltchageist', 1012, 40, 45, 45, 74, 54, 50, 1, 11, 'Supposedly, the regrets of a tea ceremony master who died before perfecting his craft lingered in some matcha and became a Pokémon.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1012.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1013, 'sinistcha', 1013, 71, 60, 106, 121, 80, 70, 2, 22, 'It pretends to be tea, trying to fool people into drinking it so it can drain their life-force. Its ruse is generally unsuccessful.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1013.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1014, 'okidogi', 1014, 88, 128, 115, 58, 86, 80, 18, 922, 'After all its muscles were stimulated by the toxic chain around its neck, Okidogi transformed and gained a powerful physique.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1014.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1015, 'munkidori', 1015, 88, 75, 66, 130, 90, 106, 10, 122, 'The chain is made from toxins that enhance capabilities. It stimulated Munkidori''s brain and caused the Pokémon''s psychic powers to bloom.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1015.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1016, 'fezandipiti', 1016, 88, 91, 82, 70, 125, 99, 14, 301, 'Fezandipiti owes its beautiful looks and lovely voice to the toxic stimulants emanating from the chain wrapped around its body.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1016.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1017, 'ogerpon', 1017, 80, 120, 84, 60, 96, 110, 12, 398, 'This Pokémon''s type changes based on which mask it''s wearing. It confounds its enemies with nimble movements and kicks.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1017.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1018, 'archaludon', 1018, 90, 105, 130, 125, 65, 85, 20, 600, 'It gathers static electricity from its surroundings. The beams it launches when down on all fours are tremendously powerful.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1018.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1019, 'hydrapple', 1019, 106, 80, 110, 120, 80, 44, 18, 930, 'Seven syrpents live inside an apple made of syrup. The syrpent in the center is the commander.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1019.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1020, 'gouging-fire', 1020, 105, 115, 121, 65, 93, 91, 35, 5900, 'There are scant few reports of this creature being sighted. One short video shows it rampaging and spouting pillars of flame.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1020.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1021, 'raging-bolt', 1021, 125, 73, 91, 137, 89, 75, 52, 4800, 'It''s said to incinerate everything around it with lightning launched from its fur. Very little is known about this creature.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1021.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1022, 'iron-boulder', 1022, 90, 120, 80, 68, 108, 124, 15, 1625, 'It resembles a Pokémon described in a dubious magazine as a Terrakion that had been modified by an evil organization.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1022.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1023, 'iron-crown', 1023, 90, 72, 100, 122, 108, 98, 16, 1560, 'It resembles a mysterious object introduced in a paranormal magazine as a cutting-edge weapon shaped like a Cobalion.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1023.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1024, 'terapagos', 1024, 90, 65, 85, 65, 85, 60, 2, 65, 'Terapagos protects itself using its power to transform energy into hard crystals. This Pokémon is the source of the Terastal phenomenon.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1024.png', FALSE);
INSERT INTO pokemon (id, nom, numero, pv, attaque, defense, atk_spe, def_spe, vitesse, taille, poids, description, generation_id, image_url, is_custom) VALUES (1025, 'pecharunt', 1025, 88, 88, 160, 88, 88, 88, 3, 3, 'It feeds others toxic mochi that draw out desires and capabilities. Those who eat the mochi fall under Pecharunt’s control, chained to its will.', 9, 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/1025.png', FALSE);
